/**
 * @module MediaSessionEvents
 *
 * Strongly typed event definitions emitted by a `MediaSession`.
 *
 * ## Purpose
 * Events are value objects produced by `MediaSession` and consumed by
 * the surrounding orchestration layer (transport adapters, monitoring,
 * analytics). No module inside the media layer consumes its own events.
 *
 * ## Thread Safety
 * Events are immutable once constructed. Safe to pass across async
 * boundaries without copying.
 *
 * ## Ordering
 * Events are emitted in strict chronological order within a single
 * `MediaSession` instance. Subscribers must not mutate the event payload.
 */

import type { Timestamp, SessionId, CallSid } from '../types/index.js';
import type { MediaSessionState } from './MediaSessionState.js';

/**
 * Common fields carried by every media session event.
 */
interface BaseMediaEvent {
  /** Millisecond Unix timestamp at the moment the event was created. */
  readonly timestamp: Timestamp;
  /** Unique identifier of the session that emitted this event. */
  readonly sessionId: SessionId;
  /** The telephony call identifier bound to this session. */
  readonly callSid: CallSid;
}

// ─── Lifecycle Events ─────────────────────────────────────────────────────────

/**
 * Emitted immediately after a `MediaSession` is constructed and enters
 * the CREATED state.
 */
export interface MediaCreatedEvent extends BaseMediaEvent {
  readonly type: 'media.created';
  /** Campaign identifier associated with this session. */
  readonly campaignId: string;
}

/**
 * Emitted when all components (runtime, audio engine, orchestrator,
 * provider session) have connected successfully and the session enters
 * the READY state.
 */
export interface MediaReadyEvent extends BaseMediaEvent {
  readonly type: 'media.ready';
  /** Wall-clock milliseconds elapsed from CREATED to READY. */
  readonly initDurationMs: number;
}

/**
 * Emitted when the first conversational turn begins and the session
 * transitions from READY to ACTIVE.
 */
export interface MediaStartedEvent extends BaseMediaEvent {
  readonly type: 'media.started';
}

/**
 * Emitted when the session transitions from ACTIVE to PAUSED.
 */
export interface MediaPausedEvent extends BaseMediaEvent {
  readonly type: 'media.paused';
  /** Human-readable reason for the pause. */
  readonly reason: string;
}

/**
 * Emitted when the caller speaks during agent output, triggering a
 * barge-in. The session enters the INTERRUPTED state momentarily
 * before returning to ACTIVE.
 */
export interface MediaInterruptedEvent extends BaseMediaEvent {
  readonly type: 'media.interrupted';
  /** Zero-based turn index at which the interruption occurred. */
  readonly turnIndex: number;
  /** Milliseconds of agent audio played before the interruption. */
  readonly agentAudioOffsetMs: number;
}

/**
 * Emitted when the session enters the COMPLETED state and all
 * resources have been flushed gracefully.
 */
export interface MediaCompletedEvent extends BaseMediaEvent {
  readonly type: 'media.completed';
  /** Total number of completed conversational turns. */
  readonly totalTurns: number;
  /** Total wall-clock duration of the conversation in milliseconds. */
  readonly durationMs: number;
  /** Human-readable completion reason (e.g. "goal_reached", "caller_hung_up"). */
  readonly completionReason: string;
}

/**
 * Emitted when the session enters the DESTROYED state and all
 * resources have been released.
 */
export interface MediaDestroyedEvent extends BaseMediaEvent {
  readonly type: 'media.destroyed';
  /** The state the session occupied immediately before being destroyed. */
  readonly destroyedFromState: MediaSessionState;
}

/**
 * Emitted when the session encounters an unrecoverable error and
 * transitions to the FAILED state.
 */
export interface MediaErrorEvent extends BaseMediaEvent {
  readonly type: 'media.error';
  /** Machine-readable error code. */
  readonly errorCode: string;
  /** Human-readable error description. */
  readonly errorMessage: string;
  /** The state the session occupied when the error occurred. */
  readonly failedInState: MediaSessionState;
  /** Whether the originating error was thrown by a provider component. */
  readonly providerError: boolean;
}

// ─── Union & Helpers ──────────────────────────────────────────────────────────

/**
 * Discriminated union of every event a `MediaSession` can emit.
 */
export type MediaEvent =
  | MediaCreatedEvent
  | MediaReadyEvent
  | MediaStartedEvent
  | MediaPausedEvent
  | MediaInterruptedEvent
  | MediaCompletedEvent
  | MediaDestroyedEvent
  | MediaErrorEvent;

/** Maps each event type literal to its concrete event interface. */
export type MediaEventMap = {
  [E in MediaEvent as E['type']]: E;
};

/** Union of all event type string literals. */
export type MediaEventType = MediaEvent['type'];

/** Handler signature for a typed media event. */
export type MediaEventHandler<T extends MediaEvent = MediaEvent> = (
  event: T
) => void;

/**
 * @module MediaSessionContext
 *
 * The immutable dependency bag for a single `MediaSession`.
 *
 * ## Purpose
 * `MediaSessionContext` is the single source of all shared, cross-cutting
 * dependencies for one live phone call at the media coordination layer.
 * Every dependency required to coordinate the session is declared here.
 * No component within the media layer may reach outside this context for
 * its dependencies.
 *
 * ## Immutability
 * The context object is frozen after construction via
 * `Object.freeze`. Individual fields that are objects are themselves
 * expected to be frozen by their owners. No field may be replaced at
 * runtime.
 *
 * ## Lifecycle
 * The context outlives no `MediaSession`. Once `destroy()` is called,
 * the context reference must not be used again.
 *
 * ## Thread Safety
 * `MediaSessionContext` is read-only after creation. All fields are either
 * value types or interfaces whose implementations must be individually
 * thread-safe.
 */

import type { ConversationRuntime } from '../runtime/ConversationRuntime.js';
import type { IClock } from '../runtime/RuntimeContext.js';
import type { IAudioEngine } from '../audio-engine/AudioEngine.js';
import type { IConversationOrchestrator } from '../orchestrator/ConversationOrchestrator.js';
import type { IRealtimeProviderSession } from '../orchestrator/ConversationOrchestrator.js';
import type { VoiceEngineConfig } from '../config/index.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import type { SessionId, CallSid } from '../types/index.js';

/**
 * The complete, immutable dependency context for one `MediaSession` instance.
 *
 * All fields are readonly. The object is sealed by `createMediaSessionContext`
 * with `Object.freeze` before being handed to the session.
 */
export interface MediaSessionContext {
  /**
   * The low-level conversation runtime that drives the call state machine.
   * Owned by the `MediaSession`; must be destroyed when the session ends.
   */
  readonly runtime: ConversationRuntime;

  /**
   * The audio processing engine for this call.
   * Coordinates inbound and outbound audio pipelines.
   */
  readonly audioEngine: IAudioEngine;

  /**
   * The conversation orchestrator that manages turn scheduling,
   * barge-in detection, and routing between runtime and provider session.
   */
  readonly orchestrator: IConversationOrchestrator;

  /**
   * The real-time AI provider session (e.g. OpenAI Realtime).
   * The media layer holds a reference to coordinate audio delivery
   * and interruption signalling. The orchestrator owns the session lifecycle.
   */
  readonly providerSession: IRealtimeProviderSession;

  /**
   * Frozen copy of the voice engine configuration active when the session
   * was created. Configuration does not change mid-call.
   */
  readonly config: Readonly<VoiceEngineConfig>;

  /**
   * Structured logger scoped to this specific media session.
   * Must be pre-bound with `sessionId` and `callSid` fields.
   */
  readonly logger: ILogger;

  /**
   * Metrics collector for emitting per-session and per-turn measurements.
   */
  readonly metrics: IMetricsCollector;

  /**
   * Monotonic clock used for timing calculations throughout the session.
   * Must never be replaced after context construction.
   */
  readonly clock: IClock;

  /**
   * Unique identifier for this session.
   * Convenience accessor — must match the session identifier carried by
   * the runtime context.
   */
  readonly sessionId: SessionId;

  /**
   * The telephony call identifier bound to this session.
   * Convenience accessor — must match the call identifier carried by
   * the runtime context.
   */
  readonly callSid: CallSid;

  /**
   * Campaign identifier associated with this session.
   * Used for event annotation and metrics labelling.
   */
  readonly campaignId: string;
}

/**
 * Constructs and freezes a `MediaSessionContext`.
 *
 * The returned object is deeply frozen at the top level. Callers are
 * responsible for ensuring that injected object fields are themselves
 * immutable (frozen or readonly-by-contract).
 *
 * @param fields - All required context fields.
 * @returns A frozen `MediaSessionContext`.
 */
export function createMediaSessionContext(
  fields: MediaSessionContext
): Readonly<MediaSessionContext> {
  return Object.freeze({ ...fields });
}

/**
 * @module MediaLifecycle
 *
 * Pure lifecycle decision logic for a `MediaSession`.
 *
 * ## Purpose
 * `MediaLifecycle` is a stateless decision engine. Given a current state
 * and a proposed transition, it returns whether the transition is legal
 * and, if not, why. It encodes NO timers, NO network calls, NO provider
 * references, and NO side effects.
 *
 * All state machine rules are derived from `MEDIA_VALID_TRANSITIONS` in
 * `MediaSessionState.ts`. `MediaLifecycle` is the single place where those
 * rules are enforced at runtime.
 *
 * ## Usage
 * ```typescript
 * const result = MediaLifecycle.evaluate(current, MediaSessionState.ACTIVE);
 * if (!result.allowed) {
 *   throw new VoiceEngineError(result.reason, ErrorCode.PIPELINE_ABORTED, false);
 * }
 * ```
 *
 * ## Thread Safety
 * All methods are pure functions with no shared mutable state.
 * Safe to call from any context without synchronisation.
 */

import {
  MediaSessionState,
  MEDIA_VALID_TRANSITIONS,
  MEDIA_TERMINAL_STATES,
} from './MediaSessionState.js';

/**
 * The result returned by a lifecycle decision evaluation.
 */
export type LifecycleDecision =
  | { readonly allowed: true }
  | { readonly allowed: false; readonly reason: string };

/**
 * Pure lifecycle decision functions for `MediaSession` state transitions.
 *
 * All methods are static and stateless. The class serves as a namespace.
 */
export class MediaLifecycle {
  private constructor() {
    // Namespace class — not instantiable.
  }

  /**
   * Evaluates whether a transition from `current` to `next` is legal
   * according to the media state machine.
   *
   * @param current - The state the session is currently in.
   * @param next    - The target state being requested.
   * @returns `{ allowed: true }` if the transition is legal, or
   *          `{ allowed: false, reason }` describing the violation.
   */
  static evaluate(
    current: MediaSessionState,
    next: MediaSessionState
  ): LifecycleDecision {
    const validPredecessors = MEDIA_VALID_TRANSITIONS[next];

    if (!validPredecessors.has(current)) {
      return {
        allowed: false,
        reason:
          `Illegal MediaSession state transition: ${current} → ${next}. ` +
          `Valid predecessors for ${next}: [${[...validPredecessors].join(', ') || 'none'}].`,
      };
    }

    return { allowed: true };
  }

  /**
   * Returns `true` if `state` is a terminal state from which no further
   * active transitions are possible (except DESTROYED via `destroy()`).
   *
   * @param state - The state to check.
   */
  static isTerminal(state: MediaSessionState): boolean {
    return MEDIA_TERMINAL_STATES.has(state);
  }

  /**
   * Returns `true` if transitioning to DESTROYED from `state` is legal.
   * DESTROYED is always reachable from COMPLETED or FAILED.
   *
   * @param state - The state to check.
   */
  static canDestroy(state: MediaSessionState): boolean {
    return MEDIA_VALID_TRANSITIONS[MediaSessionState.DESTROYED].has(state);
  }

  /**
   * Returns `true` if the session is allowed to accept inbound audio
   * in the given state. Audio is only processed while the session is
   * actively running (ACTIVE or INTERRUPTED).
   *
   * @param state - The state to check.
   */
  static acceptsInboundAudio(state: MediaSessionState): boolean {
    return (
      state === MediaSessionState.ACTIVE ||
      state === MediaSessionState.INTERRUPTED
    );
  }

  /**
   * Returns `true` if the session is allowed to emit outbound audio
   * in the given state. Outbound audio flows while ACTIVE or COMPLETING
   * (to allow final utterance flush).
   *
   * @param state - The state to check.
   */
  static acceptsOutboundAudio(state: MediaSessionState): boolean {
    return (
      state === MediaSessionState.ACTIVE ||
      state === MediaSessionState.COMPLETING
    );
  }

  /**
   * Returns `true` if a pause request is legal from `state`.
   *
   * @param state - The state to check.
   */
  static canPause(state: MediaSessionState): boolean {
    return MEDIA_VALID_TRANSITIONS[MediaSessionState.PAUSED].has(state);
  }

  /**
   * Returns `true` if a resume (PAUSED → ACTIVE) request is legal.
   *
   * @param state - The state to check.
   */
  static canResume(state: MediaSessionState): boolean {
    return state === MediaSessionState.PAUSED;
  }

  /**
   * Returns `true` if an interruption can be signalled from `state`.
   *
   * @param state - The state to check.
   */
  static canInterrupt(state: MediaSessionState): boolean {
    return MEDIA_VALID_TRANSITIONS[MediaSessionState.INTERRUPTED].has(state);
  }

  /**
   * Returns `true` if a graceful completion can be requested from `state`.
   *
   * @param state - The state to check.
   */
  static canComplete(state: MediaSessionState): boolean {
    return MEDIA_VALID_TRANSITIONS[MediaSessionState.COMPLETING].has(state);
  }
}

/**
 * @module MediaCoordinator
 *
 * Coordinates all media-level concerns for a single live phone call.
 *
 * ## Purpose
 * `MediaCoordinator` is the operational brain of a `MediaSession`. It
 * coordinates inbound audio delivery, outbound audio scheduling, barge-in
 * interruption signalling, turn lifecycle events, and session shutdown.
 *
 * It contains NO transport logic, NO provider-specific logic, NO OpenAI
 * imports, NO Exotel imports, NO WebSocket, and NO HTTP. All AI and
 * telephony concerns are accessed exclusively through the abstractions
 * injected via `MediaSessionContext`.
 *
 * ## Responsibilities
 * - Deliver inbound caller audio to the provider session via the orchestrator.
 * - Relay outbound audio scheduling results from the audio engine.
 * - Accept and gate interruption signals through lifecycle policy.
 * - Drive session lifecycle transitions (start → pause → resume → complete).
 * - Drive per-turn lifecycle events (turn start / turn complete).
 * - Coordinate graceful and forced shutdown in all error scenarios.
 *
 * ## Ownership
 * Created once per `MediaSession` and torn down with it.
 * The `MediaSession` is the sole caller of every public method.
 *
 * ## Thread Safety
 * All public methods are async and must be awaited sequentially by the owner.
 * `MediaCoordinator` does not acquire locks internally.
 */

import type { MediaSessionContext } from './MediaSessionContext.js';
import type { AudioChunk } from '../audio-engine/AudioChunk.js';
import { MediaSessionState } from './MediaSessionState.js';
import { MediaLifecycle } from './MediaLifecycle.js';
import { VoiceEngineError, ErrorCode } from '../errors/index.js';
import type { Timestamp, Nullable } from '../types/index.js';
import type {
  OrchestratorEventType,
  OrchestratorEvent,
} from '../orchestrator/ConversationOrchestrator.js';

/**
 * Callback invoked by the coordinator when the session state must change.
 * The `MediaSession` registers this to propagate state transitions and
 * emit the corresponding events.
 */
export type StateTransitionCallback = (
  next: MediaSessionState,
  meta?: Readonly<Record<string, unknown>>
) => void;

/**
 * Callback invoked by the coordinator when an unrecoverable error occurs.
 */
export type ErrorCallback = (
  error: unknown,
  fromState: MediaSessionState
) => void;

/**
 * Public contract for the media coordinator.
 */
export interface IMediaCoordinator {
  /**
   * Wires orchestrator event handlers and starts the orchestrator.
   * Must be called once, after context is ready and the session is
   * transitioning from READY → ACTIVE.
   */
  start(): Promise<void>;

  /**
   * Delivers a caller audio chunk into the inbound pipeline and
   * forwards it to the provider session via the orchestrator.
   *
   * Safe to call only while the session is ACTIVE or INTERRUPTED.
   * Silently ignored in all other states.
   *
   * @param chunk - The inbound audio chunk received from the transport layer.
   * @param now   - Current monotonic timestamp (ms).
   */
  deliverInboundAudio(chunk: AudioChunk, now: Timestamp): void;

  /**
   * Signals a barge-in detected by the transport layer.
   * The coordinator validates the interruption against lifecycle policy
   * and forwards it to the orchestrator.
   *
   * @param now - Timestamp at which the interruption was detected.
   */
  signalInterruption(now: Timestamp): Promise<void>;

  /**
   * Suspends active audio processing. Only valid from ACTIVE.
   *
   * @param reason - Human-readable reason for the pause.
   */
  pause(reason: string): Promise<void>;

  /**
   * Resumes a paused session. Only valid from PAUSED.
   */
  resume(): Promise<void>;

  /**
   * Requests a graceful shutdown. Transitions the session towards COMPLETING.
   *
   * @param reason - Human-readable completion reason.
   */
  requestCompletion(reason: string): Promise<void>;

  /**
   * Forces an immediate teardown of all coordinated components.
   * Safe to call from any state. Idempotent — subsequent calls are no-ops.
   */
  destroy(): void;
}

/**
 * Production implementation of `IMediaCoordinator`.
 */
export class MediaCoordinator implements IMediaCoordinator {
  private readonly _ctx: Readonly<MediaSessionContext>;
  private readonly _onTransition: StateTransitionCallback;
  private readonly _onError: ErrorCallback;

  private _state: MediaSessionState = MediaSessionState.CREATED;
  private _destroyed = false;
  private _startedAt: Nullable<Timestamp> = null;
  private _turnIndex = 0;
  private _lastInterruptionOffsetMs = 0;

  constructor(
    ctx: Readonly<MediaSessionContext>,
    onTransition: StateTransitionCallback,
    onError: ErrorCallback
  ) {
    this._ctx = ctx;
    this._onTransition = onTransition;
    this._onError = onError;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  async start(): Promise<void> {
    this._assertNotDestroyed('start');

    this._registerOrchestratorHandlers();
    this._ctx.logger.info('MediaCoordinator starting orchestrator');

    try {
      await this._ctx.orchestrator.start();
      this._startedAt = this._ctx.clock.now();
      this._ctx.audioEngine.start();

      this._setState(MediaSessionState.ACTIVE);
      this._ctx.logger.info('MediaCoordinator active');
    } catch (err) {
      this._ctx.logger.error('MediaCoordinator failed to start', {
        error: String(err),
      });
      throw err;
    }
  }

  deliverInboundAudio(chunk: AudioChunk, now: Timestamp): void {
    if (this._destroyed) return;
    if (!MediaLifecycle.acceptsInboundAudio(this._state)) return;

    this._ctx.audioEngine.ingestInbound(chunk);
    this._ctx.orchestrator.handleAudioChunk(
      typeof chunk.payload === 'string'
        ? chunk.payload
        : Buffer.from(chunk.payload).toString('base64'),
      now
    );
  }

  async signalInterruption(now: Timestamp): Promise<void> {
    if (this._destroyed) return;
    if (!MediaLifecycle.canInterrupt(this._state)) return;

    const agentOffset = this._resolveAgentAudioOffset(now);
    this._setState(MediaSessionState.INTERRUPTED, { turnIndex: this._turnIndex });

    try {
      this._ctx.audioEngine.flushOutbound();
      await this._ctx.orchestrator.interrupt(now);
    } catch (err) {
      this._ctx.logger.error('MediaCoordinator: interruption failed', {
        error: String(err),
      });
      this._onError(err, MediaSessionState.INTERRUPTED);
      return;
    }

    this._lastInterruptionOffsetMs = agentOffset;
    this._setState(MediaSessionState.ACTIVE, {
      turnIndex: this._turnIndex,
      agentAudioOffsetMs: agentOffset,
    });
  }

  async pause(reason: string): Promise<void> {
    this._assertNotDestroyed('pause');
    this._assertCanTransition(MediaSessionState.PAUSED, 'pause');

    this._ctx.logger.info('MediaCoordinator pausing', { reason });
    this._setState(MediaSessionState.PAUSED, { reason });
  }

  async resume(): Promise<void> {
    this._assertNotDestroyed('resume');
    if (!MediaLifecycle.canResume(this._state)) {
      throw new VoiceEngineError(
        `MediaCoordinator.resume() called from illegal state: ${this._state}`,
        ErrorCode.PIPELINE_ABORTED,
        false
      );
    }

    this._ctx.logger.info('MediaCoordinator resuming');
    this._setState(MediaSessionState.ACTIVE);
  }

  async requestCompletion(reason: string): Promise<void> {
    this._assertNotDestroyed('requestCompletion');
    if (!MediaLifecycle.canComplete(this._state)) return;

    this._ctx.logger.info('MediaCoordinator requesting completion', { reason });
    this._setState(MediaSessionState.COMPLETING, { reason });

    try {
      await this._ctx.orchestrator.stop(reason);
    } catch (err) {
      this._ctx.logger.error('MediaCoordinator: orchestrator stop failed', {
        error: String(err),
      });
    }

    this._ctx.audioEngine.stop();
    this._setState(MediaSessionState.COMPLETED, {
      reason,
      durationMs: this._uptimeMs(),
      totalTurns: this._ctx.orchestrator.getContext().completedTurnCount,
    });
  }

  destroy(): void {
    if (this._destroyed) return;
    this._destroyed = true;
    this._ctx.logger.info('MediaCoordinator destroying');

    try {
      this._ctx.orchestrator.destroy();
    } catch {
      // Swallow — destroy must never throw.
    }

    try {
      this._ctx.audioEngine.destroy();
    } catch {
      // Swallow — destroy must never throw.
    }
  }

  // ─── Orchestrator Event Wiring ─────────────────────────────────────────────

  private _registerOrchestratorHandlers(): void {
    const handle = (
      type: OrchestratorEventType,
      fn: (event: OrchestratorEvent) => void
    ): void => {
      this._ctx.orchestrator.on(type, fn);
    };

    handle('orchestrator.turn_started', (event) => {
      this._turnIndex = (event.payload['turnIndex'] as number) ?? this._turnIndex;
      this._ctx.logger.debug('Turn started', {
        turnId: event.payload['turnId'],
        turnIndex: this._turnIndex,
      });
    });

    handle('orchestrator.turn_completed', (event) => {
      this._ctx.logger.debug('Turn completed', {
        turnId: event.payload['turnId'],
        turnIndex: event.payload['turnIndex'],
      });
    });

    handle('orchestrator.turn_failed', (event) => {
      this._ctx.logger.warn('Turn failed', {
        turnId: event.payload['turnId'],
        reason: event.payload['reason'],
      });
    });

    handle('orchestrator.completed', (event) => {
      if (this._state === MediaSessionState.COMPLETING || this._state === MediaSessionState.ACTIVE) {
        const reason = String(event.payload['reason'] ?? 'completed');
        this._ctx.logger.info('Orchestrator signalled completion', { reason });
        // Drive the completing→completed transition if not already completing.
        this.requestCompletion(reason).catch((err) => {
          this._ctx.logger.error('Post-orchestrator completion failed', {
            error: String(err),
          });
        });
      }
    });

    handle('orchestrator.failed', (event) => {
      const reason = String(event.payload['reason'] ?? 'unknown');
      this._ctx.logger.error('Orchestrator failed', { reason });
      this._onError(
        new VoiceEngineError(reason, ErrorCode.PIPELINE_ABORTED, false),
        this._state
      );
    });
  }

  // ─── Private Helpers ────────────────────────────────────────────────────────

  private _setState(
    next: MediaSessionState,
    meta?: Readonly<Record<string, unknown>>
  ): void {
    this._state = next;
    this._onTransition(next, meta);
  }

  private _assertNotDestroyed(method: string): void {
    if (this._destroyed) {
      throw new VoiceEngineError(
        `MediaCoordinator.${method}() called after destroy()`,
        ErrorCode.PIPELINE_ABORTED,
        false
      );
    }
  }

  private _assertCanTransition(
    next: MediaSessionState,
    method: string
  ): void {
    const result = MediaLifecycle.evaluate(this._state, next);
    if (!result.allowed) {
      throw new VoiceEngineError(
        `MediaCoordinator.${method}(): ${result.reason}`,
        ErrorCode.PIPELINE_ABORTED,
        false
      );
    }
  }

  private _resolveAgentAudioOffset(now: Timestamp): number {
    const snapshot = this._ctx.audioEngine.getSnapshot();
    return snapshot.outboundBufferDurationMs > 0
      ? snapshot.outboundBufferDurationMs
      : 0;
  }

  private _uptimeMs(): number {
    return this._startedAt !== null
      ? this._ctx.clock.now() - this._startedAt
      : 0;
  }
}

/**
 * @module MediaSession
 *
 * The top-level coordinator for a single live phone call at the media layer.
 *
 * ## Purpose
 * `MediaSession` is the single object that owns and orchestrates every
 * component required to run one live conversation:
 *
 * - `ConversationRuntime`     — low-level call state machine
 * - `ConversationOrchestrator` — turn scheduling and barge-in logic
 * - `IAudioEngine`            — inbound/outbound audio pipelines
 * - `IRealtimeProviderSession`— abstract AI provider session
 * - `MediaCoordinator`        — wires the above into a coherent lifecycle
 *
 * `MediaSession` contains NO transport logic, NO Exotel logic, NO OpenAI
 * imports, NO WebSocket, and NO HTTP. Every concern below the media
 * coordination layer is accessed exclusively through the injected
 * `MediaSessionContext`.
 *
 * ## Ownership
 * One `MediaSession` is created per inbound or outbound call by
 * `MediaSessionFactory`. The owner is responsible for calling `destroy()`
 * when the call ends, regardless of success or failure.
 *
 * ## Thread Safety
 * Lifecycle methods are async and must be awaited sequentially by the owner.
 * Concurrent calls to lifecycle methods on the same instance produce
 * undefined behaviour. `MediaSession` does not acquire locks internally.
 *
 * ## Lifecycle
 * ```
 * createMediaSession()
 *   └─► initialize()     — CREATED → INITIALIZING → READY
 *         └─► start()    — READY → ACTIVE (conversation flowing)
 *               ├─► pause(reason)           — ACTIVE → PAUSED
 *               │     └─► resume()          — PAUSED → ACTIVE
 *               ├─► signalInterruption(now) — ACTIVE → INTERRUPTED → ACTIVE
 *               └─► complete(reason)        — ACTIVE | PAUSED → COMPLETING → COMPLETED
 *
 * Any state ──► destroy()   — COMPLETED | FAILED → DESTROYED
 * ```
 */

import type { MediaSessionContext } from './MediaSessionContext.js';
import type { AudioChunk } from '../audio-engine/AudioChunk.js';
import {
  MediaSessionState,
  MEDIA_VALID_TRANSITIONS,
} from './MediaSessionState.js';
import { MediaLifecycle } from './MediaLifecycle.js';
import { MediaCoordinator } from './MediaCoordinator.js';
import type {
  MediaEvent,
  MediaEventType,
  MediaEventHandler,
  MediaCreatedEvent,
  MediaReadyEvent,
  MediaStartedEvent,
  MediaPausedEvent,
  MediaInterruptedEvent,
  MediaCompletedEvent,
  MediaDestroyedEvent,
  MediaErrorEvent,
} from './MediaSessionEvents.js';
import { VoiceEngineError, ErrorCode } from '../errors/index.js';
import type { Timestamp, Nullable } from '../types/index.js';

// ─── Public Interface ──────────────────────────────────────────────────────────

/**
 * Public contract for a single `MediaSession` instance.
 */
export interface IMediaSession {
  /** The unique session identifier. */
  readonly sessionId: string;

  /** The current lifecycle state of the session. */
  readonly state: MediaSessionState;

  /**
   * Wires all components and transitions CREATED → INITIALIZING → READY.
   *
   * @throws {VoiceEngineError} if called from an illegal state.
   * @throws {VoiceEngineError} if any component fails to initialise.
   */
  initialize(): Promise<void>;

  /**
   * Begins the first conversational turn. Transitions READY → ACTIVE.
   *
   * @throws {VoiceEngineError} if called from an illegal state.
   */
  start(): Promise<void>;

  /**
   * Delivers a raw inbound audio chunk into the audio pipeline.
   * Silently ignored if the session is not in an audio-accepting state.
   *
   * @param chunk - Inbound audio from the transport adapter.
   * @param now   - Current monotonic timestamp in milliseconds.
   */
  deliverInboundAudio(chunk: AudioChunk, now: Timestamp): void;

  /**
   * Signals a barge-in detected by the transport adapter.
   * Transitions ACTIVE → INTERRUPTED → ACTIVE if policy permits.
   *
   * @param now - Timestamp at which the interruption was detected.
   */
  signalInterruption(now: Timestamp): Promise<void>;

  /**
   * Temporarily suspends audio processing. Transitions ACTIVE → PAUSED.
   *
   * @param reason - Human-readable reason for the pause.
   * @throws {VoiceEngineError} if called from an illegal state.
   */
  pause(reason: string): Promise<void>;

  /**
   * Resumes a paused session. Transitions PAUSED → ACTIVE.
   *
   * @throws {VoiceEngineError} if called from an illegal state.
   */
  resume(): Promise<void>;

  /**
   * Requests a graceful completion. Transitions ACTIVE | PAUSED →
   * COMPLETING → COMPLETED.
   *
   * @param reason - Human-readable completion reason.
   */
  complete(reason: string): Promise<void>;

  /**
   * Releases all resources and transitions COMPLETED | FAILED → DESTROYED.
   * Safe to call multiple times; subsequent calls are no-ops.
   */
  destroy(): void;

  /** Subscribes to a typed session event. */
  on<T extends MediaEventType>(
    type: T,
    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
  ): void;

  /** Unsubscribes from a typed session event. */
  off<T extends MediaEventType>(
    type: T,
    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
  ): void;
}

// ─── Implementation ────────────────────────────────────────────────────────────

/**
 * Production implementation of `IMediaSession`.
 */
export class MediaSession implements IMediaSession {
  private readonly _ctx: Readonly<MediaSessionContext>;
  private readonly _coordinator: MediaCoordinator;

  private _state: MediaSessionState = MediaSessionState.CREATED;
  private _createdAt: Timestamp;
  private _readyAt: Nullable<Timestamp> = null;
  private _destroyed = false;

  private readonly _handlers = new Map<
    MediaEventType,
    Set<MediaEventHandler>
  >();

  constructor(ctx: Readonly<MediaSessionContext>) {
    this._ctx = ctx;
    this._createdAt = ctx.clock.now();

    this._coordinator = new MediaCoordinator(
      ctx,
      this._handleTransition.bind(this),
      this._handleError.bind(this)
    );

    this._emit({
      type: 'media.created',
      timestamp: this._createdAt,
      sessionId: ctx.sessionId,
      callSid: ctx.callSid,
      campaignId: ctx.campaignId,
    } satisfies MediaCreatedEvent);
  }

  // ─── Accessors ─────────────────────────────────────────────────────────────

  get sessionId(): string {
    return this._ctx.sessionId;
  }

  get state(): MediaSessionState {
    return this._state;
  }

  // ─── Lifecycle ──────────────────────────────────────────────────────────────

  async initialize(): Promise<void> {
    this._assertNotDestroyed('initialize');
    this._assertTransition(MediaSessionState.INITIALIZING, 'initialize');

    this._ctx.logger.info('MediaSession initializing', {
      sessionId: this._ctx.sessionId,
      callSid: this._ctx.callSid,
    });

    this._setState(MediaSessionState.INITIALIZING);

    try {
      await this._ctx.runtime.initialize();
      await this._ctx.runtime.connect();
    } catch (err) {
      this._transitionToFailed(err, MediaSessionState.INITIALIZING, false);
      throw err;
    }

    const now = this._ctx.clock.now();
    this._readyAt = now;
    this._setState(MediaSessionState.READY);

    this._emit({
      type: 'media.ready',
      timestamp: now,
      sessionId: this._ctx.sessionId,
      callSid: this._ctx.callSid,
      initDurationMs: now - this._createdAt,
    } satisfies MediaReadyEvent);

    this._ctx.logger.info('MediaSession ready', {
      initDurationMs: now - this._createdAt,
    });
  }

  async start(): Promise<void> {
    this._assertNotDestroyed('start');
    this._assertTransition(MediaSessionState.ACTIVE, 'start');

    this._ctx.logger.info('MediaSession starting');

    try {
      await this._coordinator.start();
    } catch (err) {
      this._transitionToFailed(err, MediaSessionState.READY, false);
      throw err;
    }

    this._emit({
      type: 'media.started',
      timestamp: this._ctx.clock.now(),
      sessionId: this._ctx.sessionId,
      callSid: this._ctx.callSid,
    } satisfies MediaStartedEvent);
  }

  deliverInboundAudio(chunk: AudioChunk, now: Timestamp): void {
    if (this._destroyed) return;
    this._coordinator.deliverInboundAudio(chunk, now);
  }

  async signalInterruption(now: Timestamp): Promise<void> {
    if (this._destroyed) return;
    await this._coordinator.signalInterruption(now);
  }

  async pause(reason: string): Promise<void> {
    this._assertNotDestroyed('pause');
    await this._coordinator.pause(reason);
  }

  async resume(): Promise<void> {
    this._assertNotDestroyed('resume');
    await this._coordinator.resume();
  }

  async complete(reason: string): Promise<void> {
    this._assertNotDestroyed('complete');
    await this._coordinator.requestCompletion(reason);
  }

  destroy(): void {
    if (this._destroyed) return;
    this._destroyed = true;

    const fromState = this._state;
    this._ctx.logger.info('MediaSession destroying', { fromState });

    this._coordinator.destroy();
    this._ctx.runtime.destroy();

    this._state = MediaSessionState.DESTROYED;

    this._emit({
      type: 'media.destroyed',
      timestamp: this._ctx.clock.now(),
      sessionId: this._ctx.sessionId,
      callSid: this._ctx.callSid,
      destroyedFromState: fromState,
    } satisfies MediaDestroyedEvent);

    this._handlers.clear();
  }

  // ─── Event Bus ──────────────────────────────────────────────────────────────

  on<T extends MediaEventType>(
    type: T,
    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
  ): void {
    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
    this._handlers.get(type)!.add(handler as MediaEventHandler);
  }

  off<T extends MediaEventType>(
    type: T,
    handler: MediaEventHandler<Extract<MediaEvent, { type: T }>>
  ): void {
    this._handlers.get(type)?.delete(handler as MediaEventHandler);
  }

  // ─── Internal Transition Handlers ────────────────────────────────────────────

  /**
   * Called by `MediaCoordinator` whenever a state transition occurs.
   */
  private _handleTransition(
    next: MediaSessionState,
    meta?: Readonly<Record<string, unknown>>
  ): void {
    if (this._destroyed) return;

    const prev = this._state;
    this._state = next;

    this._ctx.logger.debug('MediaSession state transition', {
      from: prev,
      to: next,
    });

    const now = this._ctx.clock.now();

    switch (next) {
      case MediaSessionState.PAUSED:
        this._emit({
          type: 'media.paused',
          timestamp: now,
          sessionId: this._ctx.sessionId,
          callSid: this._ctx.callSid,
          reason: String(meta?.['reason'] ?? 'requested'),
        } satisfies MediaPausedEvent);
        break;

      case MediaSessionState.INTERRUPTED:
        this._emit({
          type: 'media.interrupted',
          timestamp: now,
          sessionId: this._ctx.sessionId,
          callSid: this._ctx.callSid,
          turnIndex: (meta?.['turnIndex'] as number) ?? 0,
          agentAudioOffsetMs: (meta?.['agentAudioOffsetMs'] as number) ?? 0,
        } satisfies MediaInterruptedEvent);
        break;

      case MediaSessionState.COMPLETED:
        this._emit({
          type: 'media.completed',
          timestamp: now,
          sessionId: this._ctx.sessionId,
          callSid: this._ctx.callSid,
          totalTurns: (meta?.['totalTurns'] as number) ?? 0,
          durationMs: (meta?.['durationMs'] as number) ?? 0,
          completionReason: String(meta?.['reason'] ?? 'completed'),
        } satisfies MediaCompletedEvent);
        break;

      default:
        break;
    }
  }

  /**
   * Called by `MediaCoordinator` when an unrecoverable error occurs.
   */
  private _handleError(
    error: unknown,
    fromState: MediaSessionState
  ): void {
    if (this._destroyed) return;
    this._transitionToFailed(error, fromState, true);
  }

  // ─── Private Helpers ────────────────────────────────────────────────────────

  private _setState(next: MediaSessionState): void {
    this._state = next;
  }

  private _assertNotDestroyed(method: string): void {
    if (this._destroyed) {
      throw new VoiceEngineError(
        `MediaSession.${method}() called after destroy()`,
        ErrorCode.PIPELINE_ABORTED,
        false,
        { sessionId: this._ctx.sessionId }
      );
    }
  }

  private _assertTransition(next: MediaSessionState, method: string): void {
    const result = MediaLifecycle.evaluate(this._state, next);
    if (!result.allowed) {
      throw new VoiceEngineError(
        `MediaSession.${method}(): ${result.reason}`,
        ErrorCode.PIPELINE_ABORTED,
        false,
        { sessionId: this._ctx.sessionId, currentState: this._state }
      );
    }
  }

  private _transitionToFailed(
    error: unknown,
    fromState: MediaSessionState,
    providerError: boolean
  ): void {
    const legalPredecessors = MEDIA_VALID_TRANSITIONS[MediaSessionState.FAILED];
    if (!legalPredecessors.has(fromState)) return;

    this._state = MediaSessionState.FAILED;

    const engineError =
      error instanceof VoiceEngineError
        ? error
        : new VoiceEngineError(
            String(error),
            ErrorCode.PIPELINE_ABORTED,
            false
          );

    this._ctx.logger.error('MediaSession failed', {
      errorCode: engineError.code,
      errorMessage: engineError.message,
      failedInState: fromState,
    });

    this._emit({
      type: 'media.error',
      timestamp: this._ctx.clock.now(),
      sessionId: this._ctx.sessionId,
      callSid: this._ctx.callSid,
      errorCode: engineError.code,
      errorMessage: engineError.message,
      failedInState: fromState,
      providerError,
    } satisfies MediaErrorEvent);
  }

  private _emit(event: MediaEvent): void {
    const handlers = this._handlers.get(event.type);
    if (!handlers) return;
    Array.from(handlers).forEach((handler) => {
      try {
        handler(event);
      } catch {
        // Swallow — event delivery must never crash the session.
      }
    });
  }
}

/**
 * @module MediaSessionFactory
 *
 * Dependency-injected factory for constructing `MediaSession` instances.
 *
 * ## Purpose
 * `MediaSessionFactory` is the single authoritative entry point for creating
 * `MediaSession` objects. It centralises all wiring of per-session dependencies,
 * ensures the `MediaSessionContext` is fully populated and frozen before the
 * session is returned, and emits a CREATED event before handing the session
 * to the caller.
 *
 * ## Ownership
 * The factory is a stateless singleton owned by the application bootstrap layer.
 * It does not hold any per-call state. Concurrent calls each produce an
 * independent `MediaSession` instance with no shared mutable state.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Exotel imports.
 * - No WebSocket or HTTP.
 * - No `process.env`.
 * - All dependencies are supplied by the caller via `MediaSessionDependencies`.
 */

import type { ConversationRuntime } from '../runtime/ConversationRuntime.js';
import type { IAudioEngine } from '../audio-engine/AudioEngine.js';
import type {
  IConversationOrchestrator,
  IRealtimeProviderSession,
} from '../orchestrator/ConversationOrchestrator.js';
import type { IClock } from '../runtime/RuntimeContext.js';
import type { VoiceEngineConfig } from '../config/index.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import type { SessionId, CallSid } from '../types/index.js';
import { createMediaSessionContext } from './MediaSessionContext.js';
import { MediaSession } from './MediaSession.js';
import type { IMediaSession } from './MediaSession.js';

/**
 * All dependencies required to construct a `MediaSession`.
 *
 * Every field is required. The factory performs no defaulting and no
 * resolution of optional fields. All injected objects must be fully
 * initialised before being passed to `createMediaSession`.
 */
export interface MediaSessionDependencies {
  /**
   * The low-level conversation runtime that drives the call state machine.
   * Must be in the CREATED state when passed to the factory.
   */
  readonly runtime: ConversationRuntime;

  /**
   * The audio processing engine for this call.
   * Must not yet be started — `MediaCoordinator` calls `start()` internally.
   */
  readonly audioEngine: IAudioEngine;

  /**
   * The conversation orchestrator that manages turn scheduling and barge-in.
   * Must be in the IDLE state when passed to the factory.
   */
  readonly orchestrator: IConversationOrchestrator;

  /**
   * The real-time AI provider session.
   * Must not be connected — `ConversationOrchestrator.start()` calls `connect()`.
   */
  readonly providerSession: IRealtimeProviderSession;

  /**
   * Frozen voice engine configuration snapshot for this call.
   */
  readonly config: Readonly<VoiceEngineConfig>;

  /**
   * Structured logger. Should already be bound with `sessionId` and `callSid`.
   */
  readonly logger: ILogger;

  /**
   * Metrics collector scoped to this call.
   */
  readonly metrics: IMetricsCollector;

  /**
   * Monotonic clock. Shared across all components in this session.
   */
  readonly clock: IClock;

  /**
   * Unique identifier for this session.
   */
  readonly sessionId: SessionId;

  /**
   * Telephony call identifier bound to this session.
   */
  readonly callSid: CallSid;

  /**
   * Campaign identifier associated with this session.
   */
  readonly campaignId: string;
}

/**
 * Public interface for the media session factory.
 *
 * Implementations must be stateless — all per-call state lives inside
 * the produced `IMediaSession`, not in the factory.
 */
export interface IMediaSessionFactory {
  /**
   * Constructs and returns a new `IMediaSession` in the CREATED state.
   *
   * The returned session has not been initialised. The caller must invoke
   * `initialize()` and then `start()` before audio processing can begin.
   *
   * @param deps - Fully wired per-call dependencies.
   * @returns A new `IMediaSession` in the CREATED state.
   */
  createMediaSession(deps: MediaSessionDependencies): IMediaSession;
}

/**
 * Production implementation of `IMediaSessionFactory`.
 *
 * Construct once at bootstrap and reuse across all calls.
 */
export class MediaSessionFactory implements IMediaSessionFactory {
  /**
   * Constructs a new `MediaSession` from the provided dependencies.
   *
   * Steps performed by this method:
   * 1. Assembles and freezes a `MediaSessionContext` from `deps`.
   * 2. Constructs a `MediaSession` (which emits `media.created`).
   * 3. Returns the session in the CREATED state.
   *
   * @param deps - All per-call dependencies, fully initialised.
   * @returns A new `IMediaSession` in the CREATED state.
   */
  createMediaSession(deps: MediaSessionDependencies): IMediaSession {
    const ctx = createMediaSessionContext({
      runtime: deps.runtime,
      audioEngine: deps.audioEngine,
      orchestrator: deps.orchestrator,
      providerSession: deps.providerSession,
      config: deps.config,
      logger: deps.logger.child({
        component: 'MediaSession',
        sessionId: deps.sessionId,
        callSid: deps.callSid,
      }),
      metrics: deps.metrics,
      clock: deps.clock,
      sessionId: deps.sessionId,
      callSid: deps.callSid,
      campaignId: deps.campaignId,
    });

    return new MediaSession(ctx);
  }
}

/**
 * Convenience function — constructs a `MediaSession` using the given factory
 * and dependencies. Mirrors the pattern used by `createConversationRuntime`.
 *
 * @param factory - Factory implementation to delegate to.
 * @param deps    - Per-call dependencies.
 * @returns A new `IMediaSession` in the CREATED state.
 *
 * @example
 * ```typescript
 * const session = createMediaSession(factory, deps);
 * await session.initialize();
 * await session.start();
 * session.on('media.completed', (event) => {
 *   logger.info('Call ended', { durationMs: event.durationMs });
 * });
 * ```
 */
export function createMediaSession(
  factory: IMediaSessionFactory,
  deps: MediaSessionDependencies
): IMediaSession {
  return factory.createMediaSession(deps);
}

/**
 * @module media
 *
 * Public barrel export for the Media Session layer of Voice Engine V2.
 *
 * ## Usage
 * Import everything through this module. Never import directly from sub-files.
 *
 * ```typescript
 * import {
 *   MediaSessionState,
 *   MediaSessionFactory,
 *   createMediaSession,
 * } from '../voice-engine/media/index.js';
 * ```
 *
 * ## Architecture
 * The Media Session layer coordinates ONE live phone call. It owns:
 *
 * - `ConversationRuntime`      — low-level call state machine
 * - `ConversationOrchestrator` — turn scheduling and barge-in
 * - `IAudioEngine`             — inbound / outbound audio pipelines
 * - `IRealtimeProviderSession` — abstract AI provider session
 *
 * It contains NO transport logic, NO Exotel logic, NO OpenAI logic,
 * and NO business logic.
 */

// ─── State Machine ─────────────────────────────────────────────────────────────

export {
  MediaSessionState,
  MEDIA_TERMINAL_STATES,
  MEDIA_VALID_TRANSITIONS,
} from './MediaSessionState.js';

// ─── Events ────────────────────────────────────────────────────────────────────

export type {
  MediaCreatedEvent,
  MediaReadyEvent,
  MediaStartedEvent,
  MediaPausedEvent,
  MediaInterruptedEvent,
  MediaCompletedEvent,
  MediaDestroyedEvent,
  MediaErrorEvent,
  MediaEvent,
  MediaEventMap,
  MediaEventType,
  MediaEventHandler,
