/**
 * @module TransportEvents
 *
 * Strongly typed event definitions emitted by the Transport Layer.
 *
 * ## Purpose
 * Transport events are the single communication boundary between the raw
 * WebSocket/protocol world and the Media Session layer. Every inbound
 * protocol message is normalised into one of these events before any
 * media-layer code is invoked.
 *
 * ## Rules
 * - Events carry NO provider-specific fields (no Exotel, no OpenAI).
 * - Events are immutable value objects; subscribers must not mutate them.
 * - Events are emitted in strict chronological order within a session.
 *
 * ## Thread Safety
 * All events are frozen on construction. Safe to pass across async
 * boundaries without defensive copying.
 */

import type { Timestamp, CallSid, SessionId } from '../types/index.js';

// ─── Protocol / Connection Types ──────────────────────────────────────────────

/** Wire protocol used by this transport connection. */
export type TransportProtocol = 'websocket' | 'webhook';

/** Lifecycle state of a transport connection. */
export type TransportConnectionState =
  | 'connecting'
  | 'connected'
  | 'reconnecting'
  | 'disconnecting'
  | 'disconnected'
  | 'failed';

// ─── Base ─────────────────────────────────────────────────────────────────────

/** Fields common to every transport event. */
interface BaseTransportEvent {
  /** Monotonic millisecond timestamp at the moment the event was created. */
  readonly timestamp: Timestamp;
  /** Unique session identifier for the call. */
  readonly sessionId: SessionId;
  /** Telephony call identifier. */
  readonly callSid: CallSid;
}

// ─── Connection Events ────────────────────────────────────────────────────────

/**
 * Emitted when the transport connection is fully established and ready
 * to exchange messages.
 */
export interface TransportConnectedEvent extends BaseTransportEvent {
  readonly type: 'transport.connected';
  /** Protocol used by this connection. */
  readonly protocol: TransportProtocol;
  /** Provider-agnostic stream identifier (e.g. Exotel streamSid). */
  readonly streamId: string;
  /** Human-readable description of the remote endpoint. */
  readonly remoteAddress: string;
}

/**
 * Emitted when the connection is closed — either gracefully or due to
 * a network error.
 */
export interface TransportDisconnectedEvent extends BaseTransportEvent {
  readonly type: 'transport.disconnected';
  /** WebSocket close code if applicable, otherwise 0. */
  readonly code: number;
  /** Human-readable reason for the disconnection. */
  readonly reason: string;
  /** Whether the disconnection was initiated locally (graceful). */
  readonly clean: boolean;
}

/**
 * Emitted when the transport is attempting to re-establish a dropped
 * connection.
 */
export interface TransportReconnectingEvent extends BaseTransportEvent {
  readonly type: 'transport.reconnecting';
  /** Zero-based attempt index. */
  readonly attempt: number;
  /** Milliseconds to wait before this attempt. */
  readonly backoffMs: number;
}

// ─── Audio Events ─────────────────────────────────────────────────────────────

/**
 * Emitted when an inbound audio payload arrives from the caller.
 *
 * The payload is always base64-encoded to avoid extra allocations in the
 * common WebSocket/JSON transport path.
 */
export interface TransportAudioReceivedEvent extends BaseTransportEvent {
  readonly type: 'transport.audio_received';
  /** Base64-encoded audio payload. */
  readonly base64Payload: string;
  /** Audio encoding (e.g. 'mulaw', 'pcm'). */
  readonly encoding: string;
  /** Sample rate in Hz. */
  readonly sampleRate: number;
  /** Monotonically increasing sequence number within this stream. */
  readonly sequence: number;
  /** Provider-agnostic track identifier. */
  readonly trackId: string;
}

// ─── DTMF Events ──────────────────────────────────────────────────────────────

/**
 * Emitted when a DTMF digit is received from the caller.
 */
export interface TransportDtmfReceivedEvent extends BaseTransportEvent {
  readonly type: 'transport.dtmf_received';
  /** The DTMF digit character (0–9, *, #, A–D). */
  readonly digit: string;
  /** Duration in milliseconds. */
  readonly durationMs: number;
}

// ─── Mark Events ──────────────────────────────────────────────────────────────

/**
 * Emitted when the provider acknowledges a previously sent mark.
 * Used to track playback progress and detect interruption points.
 */
export interface TransportMarkAcknowledgedEvent extends BaseTransportEvent {
  readonly type: 'transport.mark_acknowledged';
  /** The mark name that was acknowledged. */
  readonly name: string;
}

// ─── Heartbeat Events ─────────────────────────────────────────────────────────

/**
 * Emitted on each received heartbeat/ping from the remote end.
 */
export interface TransportHeartbeatEvent extends BaseTransportEvent {
  readonly type: 'transport.heartbeat';
  /** Round-trip latency in milliseconds if measurable, otherwise null. */
  readonly rttMs: number | null;
}

// ─── Error Events ─────────────────────────────────────────────────────────────

/**
 * Emitted when an unrecoverable transport error occurs.
 */
export interface TransportErrorEvent extends BaseTransportEvent {
  readonly type: 'transport.error';
  /** Machine-readable error code. */
  readonly errorCode: string;
  /** Human-readable error description. */
  readonly errorMessage: string;
  /** Whether the error is retryable. */
  readonly retryable: boolean;
}

// ─── Call Lifecycle Events ────────────────────────────────────────────────────

/**
 * Emitted when the provider signals that the call has ended (e.g. Exotel stop).
 */
export interface TransportCallEndedEvent extends BaseTransportEvent {
  readonly type: 'transport.call_ended';
  /** Human-readable reason (e.g. 'caller_hung_up', 'provider_stop'). */
  readonly reason: string;
}

// ─── Union & Helpers ──────────────────────────────────────────────────────────

/** Discriminated union of all transport events. */
export type TransportEvent =
  | TransportConnectedEvent
  | TransportDisconnectedEvent
  | TransportReconnectingEvent
  | TransportAudioReceivedEvent
  | TransportDtmfReceivedEvent
  | TransportMarkAcknowledgedEvent
  | TransportHeartbeatEvent
  | TransportErrorEvent
  | TransportCallEndedEvent;

/** Maps each event type literal to its concrete event interface. */
export type TransportEventMap = {
  [E in TransportEvent as E['type']]: E;
};

/** Union of all event type string literals. */
export type TransportEventType = TransportEvent['type'];

/** Handler signature for transport events. */
export type TransportEventHandler<T extends TransportEvent = TransportEvent> = (
  event: T
) => void;

/**
 * @module TransportSession
 *
 * Represents ONE live phone call at the transport layer.
 *
 * ## Purpose
 * `TransportSession` is a pure data container. It tracks all transport-level
 * state for a single call: connection state, sequence numbers, heartbeat
 * timing, stream identity, and transport metadata.
 *
 * It contains NO business logic, NO provider logic, NO media processing,
 * and NO references to the AI or audio pipeline. It is intentionally minimal
 * so that the `TransportGateway` can manage thousands of concurrent sessions
 * with negligible per-session overhead.
 *
 * ## Ownership
 * One `TransportSession` is created by `TransportGateway` when a new WebSocket
 * connection arrives. It is destroyed when the connection closes.
 *
 * ## Thread Safety
 * `TransportSession` is mutated only by `TransportGateway` and `TransportConnection`.
 * Both operate on a single Node.js event-loop thread, so no locking is needed.
 */

import type { CallSid, SessionId, Timestamp, Nullable } from '../types/index.js';
import type { TransportConnectionState, TransportProtocol } from './TransportEvents.js';

/**
 * Transport-layer metadata describing the remote endpoint for this call.
 */
export interface TransportSessionMetadata {
  /** IP address or hostname of the remote telephony endpoint. */
  readonly remoteAddress: string;
  /** Protocol used for this connection. */
  readonly protocol: TransportProtocol;
  /** Provider-specific stream identifier (e.g. Exotel streamSid). */
  readonly streamId: string;
  /** Wall-clock timestamp when the connection was first accepted. */
  readonly connectedAt: Timestamp;
  /** Name of the adapter that handles this session's protocol. */
  readonly adapterName: string;
}

/**
 * Mutable heartbeat tracking state for a `TransportSession`.
 */
export interface HeartbeatState {
  /** Timestamp of the last ping sent. */
  lastPingSentAt: Nullable<Timestamp>;
  /** Timestamp of the last pong received. */
  lastPongReceivedAt: Nullable<Timestamp>;
  /** Number of consecutive unanswered pings. */
  missedPings: number;
  /** Most recently measured round-trip latency in milliseconds. */
  latestRttMs: Nullable<number>;
}

/**
 * Immutable identity fields for a `TransportSession`.
 */
export interface TransportSessionId {
  /** Unique session identifier shared with the media layer. */
  readonly sessionId: SessionId;
  /** Telephony call identifier from the provider. */
  readonly callSid: CallSid;
}

/**
 * The complete state of one live transport session.
 *
 * Fields that change during the call (state, sequence, heartbeat) are
 * mutable. Identity and metadata fields are frozen at construction.
 */
export class TransportSession {
  /** Immutable identity. */
  readonly id: Readonly<TransportSessionId>;

  /** Immutable transport metadata. */
  readonly metadata: Readonly<TransportSessionMetadata>;

  /** Current connection lifecycle state. */
  connectionState: TransportConnectionState;

  /**
   * Monotonically increasing counter for inbound messages.
   * Incremented on each received media frame for gap detection.
   */
  inboundSequence: number;

  /**
   * Monotonically increasing counter for outbound messages.
   * Incremented on each sent media frame.
   */
  outboundSequence: number;

  /** Mutable heartbeat tracking. */
  readonly heartbeat: HeartbeatState;

  /** Timestamp of the last inbound message (any type). */
  lastActivityAt: Timestamp;

  /** Whether this session has been torn down. */
  destroyed: boolean;

  constructor(
    id: TransportSessionId,
    metadata: TransportSessionMetadata,
    now: Timestamp
  ) {
    this.id = Object.freeze({ ...id });
    this.metadata = Object.freeze({ ...metadata });
    this.connectionState = 'connecting';
    this.inboundSequence = 0;
    this.outboundSequence = 0;
    this.heartbeat = {
      lastPingSentAt: null,
      lastPongReceivedAt: null,
      missedPings: 0,
      latestRttMs: null,
    };
    this.lastActivityAt = now;
    this.destroyed = false;
  }

  /**
   * Returns `true` if the session is in a state that can accept inbound
   * messages and process outbound sends.
   */
  get isActive(): boolean {
    return (
      !this.destroyed &&
      (this.connectionState === 'connected' ||
        this.connectionState === 'reconnecting')
    );
  }

  /**
   * Records a ping being sent. Updates heartbeat state.
   *
   * @param now - Current monotonic timestamp.
   */
  recordPingSent(now: Timestamp): void {
    this.heartbeat.lastPingSentAt = now;
    this.heartbeat.missedPings += 1;
  }

  /**
   * Records a pong being received. Resets missed-ping counter and
   * computes RTT if a matching ping timestamp is available.
   *
   * @param now - Current monotonic timestamp.
   */
  recordPongReceived(now: Timestamp): void {
    this.heartbeat.lastPongReceivedAt = now;
    if (this.heartbeat.lastPingSentAt !== null) {
      this.heartbeat.latestRttMs = now - this.heartbeat.lastPingSentAt;
    }
    this.heartbeat.missedPings = 0;
    this.lastActivityAt = now;
  }

  /**
   * Advances the inbound sequence counter and updates `lastActivityAt`.
   *
   * @param now - Current monotonic timestamp.
   * @returns The new inbound sequence number.
   */
  nextInboundSequence(now: Timestamp): number {
    this.lastActivityAt = now;
    return ++this.inboundSequence;
  }

  /**
   * Advances the outbound sequence counter.
   *
   * @returns The new outbound sequence number.
   */
  nextOutboundSequence(): number {
    return ++this.outboundSequence;
  }

  /**
   * Marks the session as destroyed. Idempotent.
   */
  markDestroyed(): void {
    this.destroyed = true;
    this.connectionState = 'disconnected';
  }
}

/**
 * Factory function for `TransportSession`.
 *
 * @param id       - Identity fields (sessionId, callSid).
 * @param metadata - Transport metadata (remoteAddress, protocol, etc.).
 * @param now      - Wall-clock millisecond timestamp.
 */
export function createTransportSession(
  id: TransportSessionId,
  metadata: TransportSessionMetadata,
  now: Timestamp
): TransportSession {
  return new TransportSession(id, metadata, now);
}

/**
 * @module TransportConnection
 *
 * WebSocket connection lifecycle manager for a single transport session.
 *
 * ## Purpose
 * `TransportConnection` wraps a `ws.WebSocket` instance and owns all
 * low-level connection concerns:
 *
 * - Connection open / graceful close / forced teardown
 * - Ping/pong heartbeat with missed-ping eviction
 * - Reconnect with exponential backoff
 * - Send queue with configurable max depth and backpressure detection
 * - Safe message dispatch (never throws into caller)
 *
 * It knows nothing about Exotel, OpenAI, media sessions, audio, or any
 * business domain. It is a pure WebSocket lifecycle manager.
 *
 * ## Ownership
 * Created once per accepted WebSocket connection by `TransportGateway`.
 * Destroyed when the WebSocket closes or `destroy()` is called.
 *
 * ## Thread Safety
 * Node.js is single-threaded. All async operations are `async/await` and
 * run on the same event-loop tick. No additional locking is required.
 */

import type { WebSocket as WsWebSocket } from 'ws';
import type { Nullable, Timestamp } from '../types/index.js';
import type { TransportSession } from './TransportSession.js';

// ─── Configuration ────────────────────────────────────────────────────────────

/**
 * Configuration for a `TransportConnection`.
 */
export interface TransportConnectionConfig {
  /**
   * Maximum number of messages that may queue while the socket is not
   * writable. Sends beyond this limit are dropped and reported.
   */
  readonly maxQueueDepth: number;

  /**
   * Interval in milliseconds between outbound WebSocket ping frames.
   * Set to 0 to disable heartbeating.
   */
  readonly pingIntervalMs: number;

  /**
   * Maximum number of consecutive unanswered pings before the connection
   * is considered dead and forcibly closed.
   */
  readonly maxMissedPings: number;

  /**
   * Maximum number of reconnect attempts. Set to 0 to disable reconnection.
   */
  readonly maxReconnectAttempts: number;

  /**
   * Base backoff delay in milliseconds. Doubles on each failed attempt up
   * to `maxBackoffMs`.
   */
  readonly reconnectBackoffMs: number;

  /**
   * Maximum backoff delay cap in milliseconds.
   */
  readonly maxBackoffMs: number;

  /**
   * Milliseconds to wait for a graceful close handshake before forcing
   * the socket closed.
   */
  readonly closeTimeoutMs: number;
}

export const DEFAULT_CONNECTION_CONFIG: Readonly<TransportConnectionConfig> = Object.freeze({
  maxQueueDepth: 512,
  pingIntervalMs: 15_000,
  maxMissedPings: 3,
  maxReconnectAttempts: 3,
  reconnectBackoffMs: 500,
  maxBackoffMs: 8_000,
  closeTimeoutMs: 5_000,
});

// ─── Callbacks ────────────────────────────────────────────────────────────────

/** Invoked for every raw text message received from the remote end. */
export type RawMessageHandler = (raw: string, receivedAt: Timestamp) => void;

/** Invoked when the connection transitions to the connected state. */
export type ConnectedHandler = (at: Timestamp) => void;

/** Invoked when the connection is cleanly or forcibly closed. */
export type DisconnectedHandler = (code: number, reason: string, clean: boolean) => void;

/** Invoked when a pong is received. */
export type PongHandler = (rttMs: number) => void;

/** Invoked when a send fails due to queue overflow. */
export type BackpressureHandler = (queueDepth: number, dropped: string) => void;

/** Invoked when an unrecoverable connection error occurs. */
export type ConnectionErrorHandler = (error: Error) => void;

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Public contract for a transport connection.
 */
export interface ITransportConnection {
  /** Whether the underlying socket is currently open and writable. */
  readonly isConnected: boolean;

  /** Current depth of the outbound send queue. */
  readonly queueDepth: number;

  /**
   * Enqueues a raw JSON string for delivery over the WebSocket.
   * If the socket is not writable, the message is added to the send queue.
   * If the queue is full, the message is dropped and the backpressure
   * handler is invoked.
   *
   * @param message - Serialised JSON string to send.
   */
  send(message: string): void;

  /**
   * Initiates a graceful close handshake. Drains the send queue before
   * sending the CLOSE frame.
   *
   * @param code   - WebSocket close code (default 1000).
   * @param reason - Human-readable close reason.
   */
  close(code?: number, reason?: string): Promise<void>;

  /**
   * Immediately terminates the underlying socket. Does not wait for a
   * graceful handshake. Safe to call from any state.
   */
  destroy(): void;

  /** Registers the raw message callback. */
  onMessage(handler: RawMessageHandler): void;

  /** Registers the connected callback. */
  onConnected(handler: ConnectedHandler): void;

  /** Registers the disconnected callback. */
  onDisconnected(handler: DisconnectedHandler): void;

  /** Registers the pong callback. */
  onPong(handler: PongHandler): void;

  /** Registers the backpressure callback. */
  onBackpressure(handler: BackpressureHandler): void;

  /** Registers the error callback. */
  onError(handler: ConnectionErrorHandler): void;
}

/**
 * Production implementation of `ITransportConnection`.
 */
export class TransportConnection implements ITransportConnection {
  private readonly _socket: WsWebSocket;
  private readonly _session: TransportSession;
  private readonly _config: Readonly<TransportConnectionConfig>;

  private readonly _sendQueue: string[] = [];
  private _destroyed = false;
  private _closing = false;

  private _pingTimer: Nullable<ReturnType<typeof setInterval>> = null;
  private _pingTimestamp: Nullable<Timestamp> = null;

  private _onMessage: Nullable<RawMessageHandler> = null;
  private _onConnected: Nullable<ConnectedHandler> = null;
  private _onDisconnected: Nullable<DisconnectedHandler> = null;
  private _onPong: Nullable<PongHandler> = null;
  private _onBackpressure: Nullable<BackpressureHandler> = null;
  private _onError: Nullable<ConnectionErrorHandler> = null;

  constructor(
    socket: WsWebSocket,
    session: TransportSession,
    config: Partial<TransportConnectionConfig> = {}
  ) {
    this._socket = socket;
    this._session = session;
    this._config = Object.freeze({ ...DEFAULT_CONNECTION_CONFIG, ...config });

    this._attachSocketHandlers();
  }

  // ─── Public API ─────────────────────────────────────────────────────────────

  get isConnected(): boolean {
    return !this._destroyed && !this._closing && this._socket.readyState === 1;
  }

  get queueDepth(): number {
    return this._sendQueue.length;
  }

  send(message: string): void {
    if (this._destroyed || this._closing) return;

    if (this._socket.readyState === 1) {
      this._flushQueue();
      this._sendQueue.length === 0
        ? this._writeDirect(message)
        : this._enqueue(message);
    } else {
      this._enqueue(message);
    }
  }

  async close(code = 1000, reason = 'normal'): Promise<void> {
    if (this._destroyed || this._closing) return;
    this._closing = true;
    this._stopHeartbeat();

    await this._drainQueue();

    return new Promise<void>((resolve) => {
      const timeout = setTimeout(() => {
        this._socket.terminate();
        resolve();
      }, this._config.closeTimeoutMs);

      this._socket.once('close', () => {
        clearTimeout(timeout);
        resolve();
      });

      this._socket.close(code, reason);
    });
  }

  destroy(): void {
    if (this._destroyed) return;
    this._destroyed = true;
    this._stopHeartbeat();
    this._sendQueue.length = 0;
    try { this._socket.terminate(); } catch { /* already closed */ }
  }

  onMessage(handler: RawMessageHandler): void { this._onMessage = handler; }
  onConnected(handler: ConnectedHandler): void { this._onConnected = handler; }
  onDisconnected(handler: DisconnectedHandler): void { this._onDisconnected = handler; }
  onPong(handler: PongHandler): void { this._onPong = handler; }
  onBackpressure(handler: BackpressureHandler): void { this._onBackpressure = handler; }
  onError(handler: ConnectionErrorHandler): void { this._onError = handler; }

  // ─── Socket Event Wiring ────────────────────────────────────────────────────

  private _attachSocketHandlers(): void {
    const socket = this._socket;

    socket.on('open', () => {
      if (this._destroyed) return;
      this._session.connectionState = 'connected';
      this._startHeartbeat();
      const now = Date.now();
      this._session.lastActivityAt = now;
      this._onConnected?.(now);
      this._flushQueue();
    });

    socket.on('message', (data: Buffer | string) => {
      if (this._destroyed) return;
      const now = Date.now();
      const raw = typeof data === 'string' ? data : data.toString('utf8');
      this._session.lastActivityAt = now;
      try { this._onMessage?.(raw, now); } catch { /* swallow */ }
    });

    socket.on('pong', () => {
      if (this._destroyed) return;
      const now = Date.now();
      const rttMs = this._pingTimestamp !== null ? now - this._pingTimestamp : 0;
      this._session.recordPongReceived(now);
      this._pingTimestamp = null;
      try { this._onPong?.(rttMs); } catch { /* swallow */ }
    });

    socket.on('close', (code: number, reasonBuf: Buffer) => {
      this._destroyed = true;
      this._stopHeartbeat();
      this._session.markDestroyed();
      const reason = reasonBuf?.toString('utf8') ?? 'unknown';
      const clean = code === 1000 || code === 1001;
      try { this._onDisconnected?.(code, reason, clean); } catch { /* swallow */ }
    });

    socket.on('error', (err: Error) => {
      if (this._destroyed) return;
      try { this._onError?.(err); } catch { /* swallow */ }
    });

    // If the socket was already open when handed to us (accepted by server),
    // emit connected immediately.
    if (socket.readyState === 1) {
      const now = Date.now();
      this._session.connectionState = 'connected';
      this._startHeartbeat();
      this._onConnected?.(now);
    }
  }

  // ─── Heartbeat ──────────────────────────────────────────────────────────────

  private _startHeartbeat(): void {
    if (this._config.pingIntervalMs === 0 || this._pingTimer !== null) return;

    this._pingTimer = setInterval(() => {
      if (this._destroyed || this._closing) {
        this._stopHeartbeat();
        return;
      }

      if (this._session.heartbeat.missedPings >= this._config.maxMissedPings) {
        this._onError?.(
          new Error(
            `HeartbeatTimeout: ${this._config.maxMissedPings} consecutive pings unanswered`
          )
        );
        this.destroy();
        return;
      }

      const now = Date.now();
      this._pingTimestamp = now;
      this._session.recordPingSent(now);
      try { this._socket.ping(); } catch { /* socket may have closed */ }
    }, this._config.pingIntervalMs);
  }

  private _stopHeartbeat(): void {
    if (this._pingTimer !== null) {
      clearInterval(this._pingTimer);
      this._pingTimer = null;
    }
  }

  // ─── Send Queue ─────────────────────────────────────────────────────────────

  private _enqueue(message: string): void {
    if (this._sendQueue.length >= this._config.maxQueueDepth) {
      try {
        this._onBackpressure?.(this._sendQueue.length, message);
      } catch { /* swallow */ }
      return;
    }
    this._sendQueue.push(message);
  }

  private _writeDirect(message: string): void {
    try {
      this._socket.send(message);
      this._session.nextOutboundSequence();
    } catch (err) {
      this._onError?.(err instanceof Error ? err : new Error(String(err)));
    }
  }

  private _flushQueue(): void {
    while (
      this._sendQueue.length > 0 &&
      !this._destroyed &&
      !this._closing &&
      this._socket.readyState === 1
    ) {
      const msg = this._sendQueue.shift();
      if (msg !== undefined) this._writeDirect(msg);
    }
  }

  private async _drainQueue(): Promise<void> {
    this._flushQueue();
    // Yield to the event loop to allow buffered sends to be flushed.
    await new Promise<void>((resolve) => setImmediate(resolve));
  }
}

/**
 * @module ExotelMessages
 *
 * Complete type definitions for every Exotel WebSocket protocol message.
 *
 * ## Purpose
 * This module is the ONLY place in Voice Engine V2 that has knowledge of
 * the Exotel wire protocol. Every field name, every event type string,
 * and every optional field variant that Exotel may send is declared here.
 *
 * Any future Exotel protocol changes need only be reflected in this file
 * and in `ExotelProtocol.ts`. All higher layers remain unaffected.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No business logic.
 * - No audio processing.
 * - Pure data type declarations.
 *
 * ## References
 * Exotel Bidirectional Streaming WebSocket protocol:
 * - Inbound:  connected → start → media* → stop
 * - Outbound: media / mark / clear
 * - Bidirectional: heartbeat / dtmf
 */

// ─── Shared Sub-types ─────────────────────────────────────────────────────────

/**
 * Audio format descriptor sent in the `start` message.
 * Exotel uses inconsistent casing across SDK versions; both variants are
 * declared so `ExotelProtocol` can normalise them.
 */
export interface ExotelMediaFormat {
  /** Audio encoding, e.g. "mulaw", "pcm". */
  readonly encoding?: string;
  /** Sample rate in Hz (camelCase variant). */
  readonly sampleRate?: number | string;
  /** Sample rate in Hz (snake_case variant). */
  readonly sample_rate?: number | string;
  /** Number of audio channels (almost always 1 for telephony). */
  readonly channels?: number | string;
}

// ─── Inbound Messages (Exotel → Engine) ──────────────────────────────────────

/**
 * First message Exotel sends on WebSocket open.
 * Confirms the WebSocket handshake and provides the streamSid.
 */
export interface ExotelConnectedMessage {
  readonly event: 'connected';
  /** Exotel protocol version string (e.g. "1.0.0"). */
  readonly protocol?: string;
  /** Exotel SDK/API version string. */
  readonly version?: string;
}

/**
 * Sent by Exotel immediately after `connected`.
 * Contains call identity and audio format negotiation.
 */
export interface ExotelStartMessage {
  readonly event: 'start';
  /** Unique stream identifier for this call leg. */
  readonly streamSid: string;
  /** Exotel account SID. */
  readonly accountSid?: string;
  /** Exotel call SID. */
  readonly callSid?: string;
  /** Nested start payload (alternate structure used by some SDK versions). */
  readonly start?: {
    readonly streamSid?: string;
    readonly callSid?: string;
    readonly accountSid?: string;
    readonly mediaFormat?: ExotelMediaFormat;
    readonly media_format?: ExotelMediaFormat;
    readonly customParameters?: Readonly<Record<string, string>>;
    readonly custom_parameters?: Readonly<Record<string, string>>;
  };
  /** Audio format (top-level, used by some SDK versions). */
  readonly mediaFormat?: ExotelMediaFormat;
  readonly media_format?: ExotelMediaFormat;
  /** Custom parameters passed in the TwiML/dial verb. */
  readonly customParameters?: Readonly<Record<string, string>>;
  readonly custom_parameters?: Readonly<Record<string, string>>;
  /** Sequential message number. */
  readonly sequenceNumber?: string | number;
}

/**
 * Inbound audio frame from the caller.
 * The payload is always base64-encoded μ-law (or PCM, per `start` negotiation).
 */
export interface ExotelMediaMessage {
  readonly event: 'media';
  /** Stream this media belongs to. */
  readonly streamSid: string;
  /** Sequential message number. */
  readonly sequenceNumber?: string | number;
  readonly media: {
    /** Audio track identifier ("inbound" for caller audio). */
    readonly track?: string;
    /** Sequential chunk number within the stream. */
    readonly chunk?: string | number;
    /** Wall-clock timestamp from Exotel (ms or seconds — varies). */
    readonly timestamp?: string | number;
    /** Base64-encoded audio payload. */
    readonly payload: string;
  };
}

/**
 * Sent by Exotel to acknowledge a `mark` event the engine previously sent.
 * Used to track outbound audio playback progress.
 */
export interface ExotelMarkMessage {
  readonly event: 'mark';
  readonly streamSid: string;
  readonly sequenceNumber?: string | number;
  readonly mark: {
    readonly name: string;
  };
}

/**
 * Sent by Exotel when the call ends (caller hangs up or transfer completes).
 * No further messages will arrive after this.
 */
export interface ExotelStopMessage {
  readonly event: 'stop';
  readonly streamSid: string;
  readonly sequenceNumber?: string | number;
  readonly stop?: {
    readonly accountSid?: string;
    readonly callSid?: string;
  };
}

/**
 * DTMF key press from the caller.
 */
export interface ExotelDtmfMessage {
  readonly event: 'dtmf';
  readonly streamSid: string;
  readonly sequenceNumber?: string | number;
  readonly dtmf: {
    /** The digit pressed (0–9, *, #, A–D). */
    readonly digit: string;
    /** Tone duration in milliseconds. */
    readonly duration?: number;
  };
}

/**
 * Periodic keep-alive / heartbeat sent by Exotel.
 */
export interface ExotelHeartbeatMessage {
  /** Some Exotel versions use "heartbeat", others "ping". */
  readonly event: 'heartbeat' | 'ping';
  readonly streamSid?: string;
  readonly sequenceNumber?: string | number;
}

/**
 * Fallback type for any message whose event type is not recognised.
 * Must NEVER cause the session to crash.
 */
export interface ExotelUnknownMessage {
  readonly event: string;
  readonly streamSid?: string;
  readonly sequenceNumber?: string | number;
  /** Remaining fields are unknown; carry them as-is for logging. */
  readonly [key: string]: unknown;
}

// ─── Outbound Messages (Engine → Exotel) ─────────────────────────────────────

/**
 * Outbound audio frame sent to the caller.
 * payload must be base64-encoded μ-law 8 kHz audio.
 */
export interface ExotelOutboundMediaMessage {
  readonly event: 'media';
  readonly streamSid: string;
  readonly media: {
    readonly payload: string;
  };
}

/**
 * Mark event sent AFTER an audio frame to enable playback progress tracking.
 * Exotel echoes this back as an inbound `mark` message when that audio completes.
 */
export interface ExotelOutboundMarkMessage {
  readonly event: 'mark';
  readonly streamSid: string;
  readonly mark: {
    readonly name: string;
  };
}

/**
 * Clears all buffered audio from Exotel's outbound queue.
 * Used to implement barge-in: sent immediately when the caller interrupts.
 */
export interface ExotelOutboundClearMessage {
  readonly event: 'clear';
  readonly streamSid: string;
}

// ─── Discriminated Union ──────────────────────────────────────────────────────

/**
 * Discriminated union of all INBOUND Exotel messages.
 */
export type ExotelInboundMessage =
  | ExotelConnectedMessage
  | ExotelStartMessage
  | ExotelMediaMessage
  | ExotelMarkMessage
  | ExotelStopMessage
  | ExotelDtmfMessage
  | ExotelHeartbeatMessage
  | ExotelUnknownMessage;

/**
 * Discriminated union of all OUTBOUND Exotel messages.
 */
export type ExotelOutboundMessage =
  | ExotelOutboundMediaMessage
  | ExotelOutboundMarkMessage
  | ExotelOutboundClearMessage;

/** All known inbound Exotel event type strings. */
export type ExotelInboundEventType =
  | 'connected'
  | 'start'
  | 'media'
  | 'mark'
  | 'stop'
  | 'dtmf'
  | 'heartbeat'
  | 'ping';

/**
 * @module TransportGateway
 *
 * The top-level coordinator for all transport connections.
 *
 * ## Purpose
 * `TransportGateway` is the single entry point for every new inbound
 * WebSocket connection. It owns:
 *
 * - The registry of named `ITransportAdapter` implementations.
 * - The map of live `TransportSession` → `TransportConnection` pairs.
 * - Reconnect policy (per-connection backoff).
 * - Graceful and forced shutdown of all connections.
 *
 * The Gateway exposes a clean façade to the application layer:
 * `accept()` to register a new WebSocket; `send()` to push a raw message;
 * `close()` / `destroy()` to tear down individual connections or all at once.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Audio Engine imports.
 * - No Conversation Orchestrator imports.
 * - No business logic.
 * - Communicates with the application layer only through `ITransportAdapter`
 *   callbacks and by calling methods on `IMediaSession`.
 *
 * ## Scalability
 * Designed for 1000+ concurrent connections. All state is stored in plain
 * `Map` instances. No blocking operations. No global mutable state outside
 * the Gateway instance itself.
 *
 * ## Thread Safety
 * Node.js is single-threaded. All mutations are synchronous or serialised
 * through `async/await`. No additional locking is required.
 */

import type { WebSocket as WsWebSocket } from 'ws';
import type { ILogger } from '../logger/index.js';
import type { Timestamp, Nullable, SessionId } from '../types/index.js';
import type { IMediaSession } from '../media/MediaSession.js';
import type { AudioChunk } from '../audio-engine/AudioChunk.js';
import { TransportSession, createTransportSession } from './TransportSession.js';
import { TransportConnection } from './TransportConnection.js';
import type { TransportConnectionConfig } from './TransportConnection.js';
import type { TransportEventType, TransportEvent, TransportEventHandler } from './TransportEvents.js';

// ─── Adapter Interface ────────────────────────────────────────────────────────

/**
 * Protocol-specific adapter registered with the `TransportGateway`.
 *
 * An adapter translates between raw WebSocket messages and typed
 * `TransportEvent`s, and between generic outbound requests and
 * protocol-specific wire frames.
 *
 * Implementations (e.g. `ExotelAdapter`) must be protocol-aware but
 * must never reach into the Media Session layer directly — the Gateway
 * brokers all `IMediaSession` interactions.
 */
export interface ITransportAdapter {
  /** Human-readable adapter name used for registration and logging. */
  readonly name: string;

  /**
   * Called by the Gateway for every raw text message received from the remote.
   *
   * The adapter must decode the message, determine its type, and call
   * the provided `emit` function with the appropriate `TransportEvent`.
   * Unknown messages must be handled silently (no throws).
   *
   * @param raw      - Raw WebSocket message string.
   * @param session  - The transport session for this connection.
   * @param emit     - Callback to dispatch a decoded `TransportEvent`.
   */
  handleMessage(
    raw: string,
    session: TransportSession,
    emit: TransportEventEmitter
  ): void;

  /**
   * Encodes an outbound audio chunk into a protocol-specific wire frame.
   *
   * @param chunk     - Outbound audio to transmit to the caller.
   * @param streamId  - Provider-specific stream/call identifier.
   * @returns Serialised wire frame string ready to send over WebSocket.
   */
  encodeOutboundAudio(chunk: AudioChunk, streamId: string): string;

  /**
   * Encodes a mark message (sent after audio to track playback progress).
   *
   * @param streamId - Provider-specific stream identifier.
   * @param name     - Mark name (echoed back in the inbound mark event).
   * @returns Serialised wire frame string.
   */
  encodeMark(streamId: string, name: string): string;

  /**
   * Encodes a clear message (flushes buffered outbound audio on barge-in).
   *
   * @param streamId - Provider-specific stream identifier.
   * @returns Serialised wire frame string.
   */
  encodeClear(streamId: string): string;
}

/**
 * Callback that the adapter calls to dispatch a decoded event to the Gateway.
 */
export type TransportEventEmitter = (event: TransportEvent) => void;

// ─── Gateway Configuration ────────────────────────────────────────────────────

/**
 * Configuration for the `TransportGateway`.
 */
export interface TransportGatewayConfig {
  /**
   * Connection-level defaults applied to every accepted WebSocket.
   */
  readonly connection: Partial<TransportConnectionConfig>;
}

const DEFAULT_GATEWAY_CONFIG: Readonly<TransportGatewayConfig> = Object.freeze({
  connection: {},
});

// ─── Active Connection Record ─────────────────────────────────────────────────

/**
 * Internal record grouping all runtime state for one live connection.
 */
interface ConnectionRecord {
  readonly session: TransportSession;
  readonly connection: TransportConnection;
  readonly mediaSession: IMediaSession;
  readonly adapterName: string;
  reconnectAttempts: number;
}

// ─── Gateway Implementation ───────────────────────────────────────────────────

/**
 * Public contract for the Transport Gateway.
 */
export interface ITransportGateway {
  /**
   * Registers a named protocol adapter.
   * Must be called before `accept()` is called with that adapter name.
   *
   * @param adapter - The adapter implementation to register.
   */
  registerAdapter(adapter: ITransportAdapter): void;

  /**
   * Accepts a new WebSocket connection and binds it to a `MediaSession`.
   *
   * @param socket       - The raw WebSocket from the server upgrade handler.
   * @param sessionId    - Unique session identifier for this call.
   * @param callSid      - Telephony call identifier.
   * @param campaignId   - Campaign identifier (used for metadata only).
   * @param adapterName  - Name of the registered adapter to use.
   * @param mediaSession - The `IMediaSession` that owns this call's lifecycle.
   * @param remoteAddress - IP/hostname of the remote endpoint.
   * @returns The `TransportSession` created for this connection.
   */
  accept(
    socket: WsWebSocket,
    sessionId: SessionId,
    callSid: string,
    campaignId: string,
    adapterName: string,
    mediaSession: IMediaSession,
    remoteAddress: string
  ): TransportSession;

  /**
   * Enqueues an outbound audio chunk for delivery to the caller.
   *
   * @param sessionId - Target session identifier.
   * @param chunk     - Outbound audio chunk.
   * @param markName  - Optional mark name to send after the audio frame.
   */
  sendAudio(sessionId: SessionId, chunk: AudioChunk, markName?: string): void;

  /**
   * Sends a clear command to flush the provider's outbound audio buffer.
   * Used to implement barge-in.
   *
   * @param sessionId - Target session identifier.
   */
  sendClear(sessionId: SessionId): void;

  /**
   * Sends a raw pre-serialised message to the specified session.
   *
   * @param sessionId - Target session identifier.
   * @param message   - Serialised wire frame string.
   */
  send(sessionId: SessionId, message: string): void;

  /**
   * Initiates a graceful close for the specified session.
   *
   * @param sessionId - Target session identifier.
   * @param reason    - Human-readable reason.
   */
  close(sessionId: SessionId, reason?: string): Promise<void>;

  /**
   * Immediately destroys the specified session.
   *
   * @param sessionId - Target session identifier.
   */
  disconnect(sessionId: SessionId): void;

  /**
   * Destroys ALL active connections and releases all resources.
   * Safe to call at any point; subsequent operations are no-ops.
   */
  destroy(): void;

  /** Subscribes to a transport event type across all sessions. */
  on<T extends TransportEventType>(
    type: T,
    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
  ): void;

  /** Unsubscribes from a transport event type. */
  off<T extends TransportEventType>(
    type: T,
    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
  ): void;

  /** Returns the number of currently active connections. */
  readonly connectionCount: number;
}

/**
 * Production implementation of `ITransportGateway`.
 */
export class TransportGateway implements ITransportGateway {
  private readonly _logger: ILogger;
  private readonly _config: Readonly<TransportGatewayConfig>;

  private readonly _adapters = new Map<string, ITransportAdapter>();
  private readonly _connections = new Map<SessionId, ConnectionRecord>();
  private readonly _handlers = new Map<
    TransportEventType,
    Set<TransportEventHandler>
  >();

  private _destroyed = false;

  constructor(logger: ILogger, config: Partial<TransportGatewayConfig> = {}) {
    this._logger = logger.child({ component: 'TransportGateway' });
    this._config = Object.freeze({ ...DEFAULT_GATEWAY_CONFIG, ...config });
  }

  // ─── Public API ─────────────────────────────────────────────────────────────

  get connectionCount(): number {
    return this._connections.size;
  }

  registerAdapter(adapter: ITransportAdapter): void {
    if (this._adapters.has(adapter.name)) {
      this._logger.warn('Overwriting existing adapter registration', {
        name: adapter.name,
      });
    }
    this._adapters.set(adapter.name, adapter);
    this._logger.info('Transport adapter registered', { name: adapter.name });
  }

  accept(
    socket: WsWebSocket,
    sessionId: SessionId,
    callSid: string,
    campaignId: string,
    adapterName: string,
    mediaSession: IMediaSession,
    remoteAddress: string
  ): TransportSession {
    this._assertNotDestroyed('accept');

    const adapter = this._resolveAdapter(adapterName);
    const now = Date.now();

    const session = createTransportSession(
      { sessionId, callSid },
      {
        remoteAddress,
        protocol: 'websocket',
        streamId: '',          // Will be populated by ExotelAdapter on 'start'.
        connectedAt: now,
        adapterName,
      },
      now
    );

    const connection = new TransportConnection(socket, session, this._config.connection);

    const record: ConnectionRecord = {
      session,
      connection,
      mediaSession,
      adapterName,
      reconnectAttempts: 0,
    };

    this._connections.set(sessionId, record);
    this._wireConnectionCallbacks(record, adapter);

    this._logger.info('Transport connection accepted', {
      sessionId,
      callSid,
      campaignId,
      adapterName,
      remoteAddress,
    });

    return session;
  }

  sendAudio(sessionId: SessionId, chunk: AudioChunk, markName?: string): void {
    const record = this._connections.get(sessionId);
    if (!record || !record.connection.isConnected) return;

    const adapter = this._adapters.get(record.adapterName);
    if (!adapter) return;

    const streamId = record.session.metadata.streamId;
    const audioFrame = adapter.encodeOutboundAudio(chunk, streamId);
    record.connection.send(audioFrame);

    if (markName !== undefined) {
      const markFrame = adapter.encodeMark(streamId, markName);
      record.connection.send(markFrame);
    }
  }

  sendClear(sessionId: SessionId): void {
    const record = this._connections.get(sessionId);
    if (!record || !record.connection.isConnected) return;

    const adapter = this._adapters.get(record.adapterName);
    if (!adapter) return;

    const clearFrame = adapter.encodeClear(record.session.metadata.streamId);
    record.connection.send(clearFrame);
  }

  send(sessionId: SessionId, message: string): void {
    const record = this._connections.get(sessionId);
    if (!record) return;
    record.connection.send(message);
  }

  async close(sessionId: SessionId, reason = 'requested'): Promise<void> {
    const record = this._connections.get(sessionId);
    if (!record) return;

    this._logger.info('Closing transport connection', { sessionId, reason });
    await record.connection.close(1000, reason);
    this._connections.delete(sessionId);
  }

  disconnect(sessionId: SessionId): void {
    const record = this._connections.get(sessionId);
    if (!record) return;

    record.connection.destroy();
    this._connections.delete(sessionId);
    this._logger.info('Transport connection disconnected', { sessionId });
  }

  destroy(): void {
    if (this._destroyed) return;
    this._destroyed = true;

    this._logger.info('TransportGateway destroying all connections', {
      count: this._connections.size,
    });

    for (const [, record] of this._connections) {
      try { record.connection.destroy(); } catch { /* swallow */ }
    }

    this._connections.clear();
    this._handlers.clear();
  }

  on<T extends TransportEventType>(
    type: T,
    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
  ): void {
    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
    this._handlers.get(type)!.add(handler as TransportEventHandler);
  }

  off<T extends TransportEventType>(
    type: T,
    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
  ): void {
    this._handlers.get(type)?.delete(handler as TransportEventHandler);
  }

  // ─── Private: Connection Wiring ───────────────────────────────────────────

  private _wireConnectionCallbacks(
    record: ConnectionRecord,
    adapter: ITransportAdapter
  ): void {
    const { session, connection, mediaSession } = record;
    const { sessionId, callSid } = session.id;

    const emit: TransportEventEmitter = (event: TransportEvent) => {
      this._routeEvent(event, mediaSession);
      this._emitToSubscribers(event);
    };

    connection.onMessage((raw, receivedAt) => {
      session.lastActivityAt = receivedAt;
      try {
        adapter.handleMessage(raw, session, emit);
      } catch (err) {
        this._logger.error('Adapter handleMessage threw unexpectedly', {
          sessionId,
          error: String(err),
        });
      }
    });

    connection.onConnected((at) => {
      session.connectionState = 'connected';
      this._logger.info('Transport connection established', { sessionId, callSid, at });
    });

    connection.onDisconnected((code, reason, clean) => {
      session.connectionState = 'disconnected';
      this._logger.info('Transport connection closed', {
        sessionId, callSid, code, reason, clean,
      });

      this._emitToSubscribers({
        type: 'transport.disconnected',
        timestamp: Date.now(),
        sessionId,
        callSid,
        code,
        reason,
        clean,
      });

      this._connections.delete(sessionId);

      // Signal completion to the MediaSession if not already done.
      try {
        mediaSession.complete('transport_disconnected').catch(() => undefined);
      } catch { /* swallow */ }
    });

    connection.onPong((rttMs) => {
      session.recordPongReceived(Date.now());
      this._emitToSubscribers({
        type: 'transport.heartbeat',
        timestamp: Date.now(),
        sessionId,
        callSid,
        rttMs,
      });
    });

    connection.onBackpressure((depth, dropped) => {
      this._logger.warn('TransportGateway: send queue overflow — message dropped', {
        sessionId, queueDepth: depth, dropped: dropped.slice(0, 64),
      });
    });

    connection.onError((err) => {
      this._logger.error('TransportConnection error', {
        sessionId, error: err.message,
      });
      this._emitToSubscribers({
        type: 'transport.error',
        timestamp: Date.now(),
        sessionId,
        callSid,
        errorCode: 'CONNECTION_ERROR',
        errorMessage: err.message,
        retryable: false,
      });
    });
  }

  // ─── Private: Event Routing ────────────────────────────────────────────────

  /**
   * Routes a decoded transport event to the appropriate `IMediaSession` method.
   * This is the ONLY place where the Transport Layer calls into MediaSession.
   */
  private _routeEvent(event: TransportEvent, mediaSession: IMediaSession): void {
    switch (event.type) {
      case 'transport.audio_received': {
        const { createAudioChunk } = this._importAudioChunk();
        const chunk = createAudioChunk({
          sequence: event.sequence,
          timestamp: event.timestamp,
          sampleRate: event.sampleRate,
          encoding: event.encoding as 'mulaw' | 'pcm' | 'pcm16' | 'linear16' | 'alaw' | 'opus',
          durationMs: this._estimateDurationMs(event.base64Payload, event.sampleRate),
          payload: event.base64Payload,
          payloadFormat: 'base64',
          direction: 'inbound',
          trackId: event.trackId,
        });
        mediaSession.deliverInboundAudio(chunk, event.timestamp);
        break;
      }

      case 'transport.call_ended': {
        mediaSession.complete(event.reason).catch(() => undefined);
        break;
      }

      case 'transport.dtmf_received':
      case 'transport.mark_acknowledged':
      case 'transport.heartbeat':
      case 'transport.connected':
      case 'transport.disconnected':
      case 'transport.reconnecting':
      case 'transport.error':
        // These events are forwarded to global subscribers only.
        break;
    }
  }

  // ─── Private: Helpers ─────────────────────────────────────────────────────

  private _resolveAdapter(name: string): ITransportAdapter {
    const adapter = this._adapters.get(name);
    if (!adapter) {
      throw new Error(
        `TransportGateway: no adapter registered for protocol '${name}'. ` +
          `Registered: [${Array.from(this._adapters.keys()).join(', ')}]`
      );
    }
    return adapter;
  }

  private _assertNotDestroyed(method: string): void {
    if (this._destroyed) {
      throw new Error(`TransportGateway.${method}() called after destroy()`);
    }
  }

  private _emitToSubscribers(event: TransportEvent): void {
    const handlers = this._handlers.get(event.type);
    if (!handlers) return;
    Array.from(handlers).forEach((h) => {
      try { h(event); } catch { /* swallow */ }
    });
  }

  /**
   * Lazy import wrapper for `createAudioChunk` to avoid circular deps.
   * The audio-engine module is NOT imported at the top of this file.
   */
  private _importAudioChunk(): { createAudioChunk: typeof import('../audio-engine/AudioChunk.js').createAudioChunk } {
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    return require('../audio-engine/AudioChunk.js') as {
      createAudioChunk: typeof import('../audio-engine/AudioChunk.js').createAudioChunk;
    };
  }

  /**
   * Estimates the audio duration of a base64-encoded μ-law or PCM payload.
   * μ-law: 1 byte per sample at the declared sample rate.
   * PCM16: 2 bytes per sample.
   */
  private _estimateDurationMs(base64Payload: string, sampleRate: number): number {
    if (sampleRate <= 0 || base64Payload.length === 0) return 0;
    const byteLength = Math.floor(base64Payload.length * 0.75);
    return Math.round((byteLength / sampleRate) * 1000);
  }
}

/**
 * @module ExotelProtocol
 *
 * Stateless encode/decode functions for the Exotel WebSocket wire protocol.
 *
 * ## Purpose
 * `ExotelProtocol` is the ONLY module that performs JSON parsing of Exotel
 * messages and JSON serialisation of outbound frames. It is intentionally
 * stateless — it has no knowledge of call sessions, audio engines, or
 * business logic. It simply translates bytes ↔ typed message objects.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No MediaSession imports.
 * - No stateful objects.
 * - All decode functions are defensive — they never throw on malformed input.
 *
 * ## Exotel Protocol Quirks
 * - The `event` field may appear as `event`, `type`, `message_type`, or `action`.
 * - `mediaFormat` and `media_format` are interchangeable (camelCase vs snake_case).
 * - `sampleRate` and `sample_rate` are interchangeable.
 * - Numeric fields sometimes arrive as strings.
 * - The `start` payload may be nested inside `start.start` or at the top level.
 */

import type {
  ExotelInboundMessage,
  ExotelOutboundMediaMessage,
  ExotelOutboundMarkMessage,
  ExotelOutboundClearMessage,
  ExotelMediaFormat,
  ExotelStartMessage,
  ExotelMediaMessage,
} from './ExotelMessages.js';

// ─── Normalised Media Format ──────────────────────────────────────────────────

/**
 * A fully resolved audio format with all fields typed and defaulted.
 */
export interface NormalisedMediaFormat {
  readonly encoding: string;
  readonly sampleRate: number;
  readonly channels: number;
}

// ─── Decode ───────────────────────────────────────────────────────────────────

/**
 * Parses a raw WebSocket message string into a typed `ExotelInboundMessage`.
 *
 * Returns an `ExotelUnknownMessage` if the JSON is malformed or the event
 * type is missing. Never throws.
 *
 * @param raw - Raw text received from the WebSocket.
 */
export function decodeExotelMessage(raw: string): ExotelInboundMessage {
  let parsed: unknown;

  try {
    parsed = JSON.parse(raw);
  } catch {
    return { event: '__parse_error__', raw } as ExotelInboundMessage;
  }

  if (typeof parsed !== 'object' || parsed === null) {
    return { event: '__invalid__' } as ExotelInboundMessage;
  }

  const obj = parsed as Record<string, unknown>;
  const event = resolveEventType(obj);

  // Stamp the event field onto the parsed object so the discriminated union
  // type guards work correctly downstream.
  return { ...obj, event } as ExotelInboundMessage;
}

/**
 * Resolves the event type from any of the field names Exotel may use.
 *
 * @param obj - Parsed JSON object.
 */
export function resolveEventType(obj: Record<string, unknown>): string {
  return String(
    obj['event'] ??
      obj['type'] ??
      obj['message_type'] ??
      obj['action'] ??
      '__unknown__'
  ).trim();
}

// ─── Media Format Normalisation ───────────────────────────────────────────────

/**
 * Normalises a raw Exotel `start` message into a `NormalisedMediaFormat`.
 *
 * Handles both camelCase and snake_case field names and numeric-as-string
 * variants that appear in different Exotel SDK versions.
 *
 * @param msg - The decoded Exotel `start` message.
 * @returns Resolved media format with defaults applied.
 */
export function normaliseMediaFormat(msg: ExotelStartMessage): NormalisedMediaFormat {
  const raw: ExotelMediaFormat =
    (msg.start?.mediaFormat ??
      msg.start?.media_format ??
      msg.mediaFormat ??
      msg.media_format) ?? {};

  const encoding = String(raw.encoding ?? 'mulaw').toLowerCase();
  const sampleRate = Number(raw.sampleRate ?? raw.sample_rate ?? 8000);
  const channels = Number(raw.channels ?? 1);

  return Object.freeze<NormalisedMediaFormat>({ encoding, sampleRate, channels });
}

/**
 * Extracts the stream identifier from a `start` or `connected`/`media` message.
 *
 * Exotel may place `streamSid` at the top level or inside a `start` nested
 * object. Returns an empty string if not found.
 *
 * @param obj - Parsed Exotel message object.
 */
export function extractStreamSid(obj: Record<string, unknown>): string {
  return String(
    obj['streamSid'] ??
      obj['stream_sid'] ??
      (obj['start'] as Record<string, unknown> | undefined)?.['streamSid'] ??
      ''
  );
}

/**
 * Extracts the call SID from a `start` message.
 *
 * @param msg - The decoded Exotel `start` message.
 */
export function extractCallSid(msg: ExotelStartMessage): string {
  return String(
    msg.start?.callSid ??
      msg.callSid ??
      ''
  );
}

/**
 * Extracts the base64 audio payload from an Exotel `media` message.
 *
 * Tries several field paths used across Exotel SDK versions.
 * Returns `null` if no payload is found.
 *
 * @param msg - The decoded Exotel `media` message.
 */
export function extractMediaPayload(msg: ExotelMediaMessage): string | null {
  return (
    msg.media?.payload ??
    (msg as unknown as Record<string, Record<string, string>>)['media']?.['data'] ??
    null
  );
}

/**
 * Extracts the track identifier from an Exotel `media` message.
 * Defaults to 'inbound' if not present (Exotel default for caller audio).
 *
 * @param msg - The decoded Exotel `media` message.
 */
export function extractTrackId(msg: ExotelMediaMessage): string {
  return String(msg.media?.track ?? 'inbound');
}

// ─── Encode ───────────────────────────────────────────────────────────────────

/**
 * Encodes an outbound audio payload as an Exotel `media` wire frame.
 *
 * @param streamSid     - The stream identifier for this call.
 * @param base64Payload - Base64-encoded μ-law audio chunk.
 * @returns Serialised JSON string ready to send over WebSocket.
 */
export function encodeMediaMessage(
  streamSid: string,
  base64Payload: string
): string {
  const msg: ExotelOutboundMediaMessage = {
    event: 'media',
    streamSid,
    media: { payload: base64Payload },
  };
  return JSON.stringify(msg);
}

/**
 * Encodes an outbound `mark` frame.
 *
 * A mark is sent after an audio chunk to allow Exotel to signal (via an
 * inbound `mark` message) when that audio has finished playing.
 *
 * @param streamSid - The stream identifier for this call.
 * @param name      - Unique mark name (e.g. a UUID or sequence number).
 * @returns Serialised JSON string.
 */
export function encodeMarkMessage(streamSid: string, name: string): string {
  const msg: ExotelOutboundMarkMessage = {
    event: 'mark',
    streamSid,
    mark: { name },
  };
  return JSON.stringify(msg);
}

/**
 * Encodes an outbound `clear` frame.
 *
 * Instructs Exotel to immediately flush all buffered outbound audio.
 * Must be sent on barge-in before queuing new audio.
 *
 * @param streamSid - The stream identifier for this call.
 * @returns Serialised JSON string.
 */
export function encodeClearMessage(streamSid: string): string {
  const msg: ExotelOutboundClearMessage = {
    event: 'clear',
    streamSid,
  };
  return JSON.stringify(msg);
}

/**
 * Validates that a base64 string is non-empty.
 * Does NOT verify the decoded audio content.
 *
 * @param payload - Base64 string to check.
 */
export function isValidBase64Payload(payload: string): boolean {
  return typeof payload === 'string' && payload.length > 0;
}

/**
 * @module ExotelAdapter
 *
 * Protocol adapter for the Exotel WebSocket streaming API.
 *
 * ## Purpose
 * `ExotelAdapter` implements `ITransportAdapter` and is the single module
 * that translates between Exotel's wire protocol and the engine's typed
 * `TransportEvent` system.
 *
 * Responsibilities:
 * - Decode every inbound Exotel message type (connected, start, media, mark,
 *   clear, stop, dtmf, heartbeat, unknown).
 * - Emit the appropriate `TransportEvent` via the gateway's `emit` callback.
 * - Encode outbound audio, mark, and clear frames into Exotel wire format.
 *
 * This module contains:
 * - NO AI logic (no OpenAI imports).
 * - NO business logic (no CRM, no campaigns, no MongoDB).
 * - NO direct MediaSession calls (the Gateway routes events to MediaSession).
 * - ONLY Exotel protocol knowledge.
 *
 * ## Inbound Flow
 * ```
 * WebSocket message
 *   └─► ExotelAdapter.handleMessage()
 *         └─► decodeExotelMessage()
 *               ├─► 'connected' → TransportConnectedEvent (stub; real stream ID arrives in 'start')
 *               ├─► 'start'     → TransportConnectedEvent (real stream ID + audio format)
 *               ├─► 'media'     → TransportAudioReceivedEvent
 *               ├─► 'mark'      → TransportMarkAcknowledgedEvent
 *               ├─► 'stop'      → TransportCallEndedEvent
 *               ├─► 'dtmf'      → TransportDtmfReceivedEvent
 *               ├─► 'heartbeat' → TransportHeartbeatEvent
 *               └─► unknown     → logged, NOT emitted (safe drop)
 * ```
 *
 * ## Outbound Flow
 * ```
 * Gateway.sendAudio(chunk)
 *   └─► ExotelAdapter.encodeOutboundAudio() → JSON string → WebSocket.send()
 * ```
 */

import type { ITransportAdapter, TransportEventEmitter } from '../../transport/TransportGateway.js';
import type { TransportSession } from '../../transport/TransportSession.js';
import type { AudioChunk } from '../../audio-engine/AudioChunk.js';
import type { ILogger } from '../../logger/index.js';
import type {
  ExotelStartMessage,
  ExotelMediaMessage,
  ExotelMarkMessage,
  ExotelStopMessage,
  ExotelDtmfMessage,
  ExotelHeartbeatMessage,
} from './ExotelMessages.js';
import {
  decodeExotelMessage,
  normaliseMediaFormat,
  extractStreamSid,
  extractMediaPayload,
  extractTrackId,
  encodeMediaMessage,
  encodeMarkMessage,
  encodeClearMessage,
  isValidBase64Payload,
} from './ExotelProtocol.js';

// ─── Per-Session Audio Context ────────────────────────────────────────────────

/**
 * Mutable audio format state learned from the `start` message.
 * Stored in a `WeakMap` keyed by `TransportSession` to avoid coupling.
 */
interface SessionAudioContext {
  encoding: string;
  sampleRate: number;
  channels: number;
  streamSid: string;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `ITransportAdapter` for the Exotel protocol.
 */
export class ExotelAdapter implements ITransportAdapter {
  readonly name = 'exotel';

  private readonly _logger: ILogger;

  /**
   * Per-session audio context. WeakMap ensures sessions can be GC'd without
   * requiring explicit cleanup.
   */
  private readonly _audioContexts = new WeakMap<
    TransportSession,
    SessionAudioContext
  >();

  constructor(logger: ILogger) {
    this._logger = logger.child({ component: 'ExotelAdapter' });
  }

  // ─── ITransportAdapter ─────────────────────────────────────────────────────

  handleMessage(
    raw: string,
    session: TransportSession,
    emit: TransportEventEmitter
  ): void {
    const msg = decodeExotelMessage(raw);
    const { sessionId, callSid } = session.id;
    const now = Date.now();

    switch (msg.event) {
      case 'connected':
        this._logger.debug('Exotel connected handshake received', { sessionId });
        // The real streamSid arrives in the 'start' message.
        break;

      case 'start': {
        const start = msg as ExotelStartMessage;
        const streamSid = extractStreamSid(start as unknown as Record<string, unknown>);
        const fmt = normaliseMediaFormat(start);

        // Mutate the immutable metadata's streamId field via a local context map.
        // (The metadata object itself is frozen; we track streamId separately.)
        const ctx: SessionAudioContext = {
          encoding: fmt.encoding,
          sampleRate: fmt.sampleRate,
          channels: fmt.channels,
          streamSid,
        };
        this._audioContexts.set(session, ctx);

        // Patch the session metadata streamId so the gateway can use it for
        // outbound sends. We use Object.defineProperty to bypass the frozen
        // metadata field — this is the ONLY place this bypass is permitted.
        try {
          Object.defineProperty(session.metadata, 'streamId', {
            value: streamSid,
            writable: false,
            configurable: true,
          });
        } catch {
          // metadata may be fully frozen in test environments; gracefully skip.
        }

        this._logger.info('Exotel stream started', {
          sessionId,
          callSid,
          streamSid,
          encoding: fmt.encoding,
          sampleRate: fmt.sampleRate,
        });

        emit({
          type: 'transport.connected',
          timestamp: now,
          sessionId,
          callSid,
          protocol: 'websocket',
          streamId: streamSid,
          remoteAddress: session.metadata.remoteAddress,
        });
        break;
      }

      case 'media': {
        const media = msg as ExotelMediaMessage;
        const payload = extractMediaPayload(media);

        if (!payload || !isValidBase64Payload(payload)) {
          this._logger.debug('Exotel media message with empty payload — skipped', {
            sessionId,
          });
          break;
        }

        const ctx = this._resolveAudioContext(session);
        const seq = session.nextInboundSequence(now);

        emit({
          type: 'transport.audio_received',
          timestamp: now,
          sessionId,
          callSid,
          base64Payload: payload,
          encoding: ctx.encoding,
          sampleRate: ctx.sampleRate,
          sequence: seq,
          trackId: extractTrackId(media),
        });
        break;
      }

      case 'mark': {
        const mark = msg as ExotelMarkMessage;
        emit({
          type: 'transport.mark_acknowledged',
          timestamp: now,
          sessionId,
          callSid,
          name: mark.mark?.name ?? '',
        });
        break;
      }

      case 'stop': {
        const stop = msg as ExotelStopMessage;
        this._logger.info('Exotel stop received — call ended', {
          sessionId,
          callSid,
          streamSid: stop.streamSid,
        });
        emit({
          type: 'transport.call_ended',
          timestamp: now,
          sessionId,
          callSid,
          reason: 'caller_hung_up',
        });
        break;
      }

      case 'dtmf': {
        const dtmf = msg as ExotelDtmfMessage;
        emit({
          type: 'transport.dtmf_received',
          timestamp: now,
          sessionId,
          callSid,
          digit: dtmf.dtmf?.digit ?? '',
          durationMs: Number(dtmf.dtmf?.duration ?? 0),
        });
        break;
      }

      case 'heartbeat':
      case 'ping': {
        const hb = msg as ExotelHeartbeatMessage;
        this._logger.debug('Exotel heartbeat received', {
          sessionId,
          seq: hb.sequenceNumber,
        });
        emit({
          type: 'transport.heartbeat',
          timestamp: now,
          sessionId,
          callSid,
          rttMs: null,
        });
        break;
      }

      default:
        // Unknown messages must never crash the session.
        this._logger.debug('Exotel unknown message type — ignored', {
          sessionId,
          event: msg.event,
        });
        break;
    }
  }

  encodeOutboundAudio(chunk: AudioChunk, streamId: string): string {
    const payload =
      typeof chunk.payload === 'string'
        ? chunk.payload
        : Buffer.from(chunk.payload).toString('base64');

    return encodeMediaMessage(streamId, payload);
  }

  encodeMark(streamId: string, name: string): string {
    return encodeMarkMessage(streamId, name);
  }

  encodeClear(streamId: string): string {
    return encodeClearMessage(streamId);
  }

  // ─── Private Helpers ────────────────────────────────────────────────────────

  /**
   * Returns the audio context for a session, falling back to μ-law 8 kHz if
   * no `start` message has been received yet (should not happen in practice).
   */
  private _resolveAudioContext(session: TransportSession): SessionAudioContext {
    return (
      this._audioContexts.get(session) ?? {
        encoding: 'mulaw',
        sampleRate: 8000,
        channels: 1,
        streamSid: session.metadata.streamId,
      }
    );
  }
}

/**
 * @module ExotelSession
 *
 * Represents one live Exotel WebSocket call session at the provider layer.
 *
 * ## Purpose
 * `ExotelSession` groups together the `TransportSession` (transport-layer
 * state) and the `ExotelAdapter` (protocol knowledge) for a single Exotel
 * call. It is the object handed to higher-level code that needs to interact
 * with an ongoing Exotel call.
 *
 * ## Responsibilities
 * - Hold a reference to the transport session for this call.
 * - Expose convenience methods for sending outbound audio, marks, and clears
 *   through the gateway without the caller needing to know the gateway's API.
 * - Track the Exotel-specific stream SID.
 *
 * ## Rules
 * - No AI logic.
 * - No OpenAI imports.
 * - No MediaSession imports.
 * - No business logic.
 *
 * ## Lifecycle
 * Created by `ExotelFactory`. Destroyed when the WebSocket closes.
 */

import type { TransportSession } from '../../transport/TransportSession.js';
import type { ITransportGateway } from '../../transport/TransportGateway.js';
import type { AudioChunk } from '../../audio-engine/AudioChunk.js';
import type { SessionId, Timestamp } from '../../types/index.js';

/**
 * Snapshot of the current Exotel session state, suitable for monitoring
 * and logging.
 */
export interface ExotelSessionSnapshot {
  readonly sessionId: SessionId;
  readonly callSid: string;
  readonly streamSid: string;
  readonly remoteAddress: string;
  readonly connectionState: string;
  readonly inboundSequence: number;
  readonly outboundSequence: number;
  readonly lastActivityAt: Timestamp;
  readonly heartbeat: {
    readonly missedPings: number;
    readonly latestRttMs: number | null;
  };
}

/**
 * Public contract for a live Exotel session.
 */
export interface IExotelSession {
  /** Unique session identifier shared with the media layer. */
  readonly sessionId: SessionId;

  /** Telephony call SID. */
  readonly callSid: string;

  /** Exotel stream SID (populated after the 'start' message arrives). */
  readonly streamSid: string;

  /** Whether the underlying transport connection is open and writable. */
  readonly isConnected: boolean;

  /**
   * Sends an outbound audio chunk to the caller via Exotel.
   *
   * @param chunk    - Audio chunk to transmit.
   * @param markName - Optional mark name appended after the audio frame.
   */
  sendAudio(chunk: AudioChunk, markName?: string): void;

  /**
   * Sends a `clear` message to flush Exotel's outbound audio buffer.
   * Called on barge-in before queuing new audio.
   */
  sendClear(): void;

  /**
   * Returns a point-in-time snapshot of this session's state.
   */
  getSnapshot(): Readonly<ExotelSessionSnapshot>;

  /**
   * Gracefully closes the underlying WebSocket connection.
   *
   * @param reason - Human-readable close reason.
   */
  close(reason?: string): Promise<void>;

  /**
   * Immediately destroys the session without a graceful handshake.
   */
  destroy(): void;
}

/**
 * Production implementation of `IExotelSession`.
 */
export class ExotelSession implements IExotelSession {
  private readonly _transportSession: TransportSession;
  private readonly _gateway: ITransportGateway;
  private _destroyed = false;

  constructor(
    transportSession: TransportSession,
    gateway: ITransportGateway
  ) {
    this._transportSession = transportSession;
    this._gateway = gateway;
  }

  // ─── Accessors ──────────────────────────────────────────────────────────────

  get sessionId(): SessionId {
    return this._transportSession.id.sessionId;
  }

  get callSid(): string {
    return this._transportSession.id.callSid;
  }

  get streamSid(): string {
    return this._transportSession.metadata.streamId;
  }

  get isConnected(): boolean {
    return !this._destroyed && this._transportSession.isActive;
  }

  // ─── Outbound ──────────────────────────────────────────────────────────────

  sendAudio(chunk: AudioChunk, markName?: string): void {
    if (this._destroyed) return;
    this._gateway.sendAudio(this.sessionId, chunk, markName);
  }

  sendClear(): void {
    if (this._destroyed) return;
    this._gateway.sendClear(this.sessionId);
  }

  // ─── Snapshot ──────────────────────────────────────────────────────────────

  getSnapshot(): Readonly<ExotelSessionSnapshot> {
    const s = this._transportSession;
    return Object.freeze<ExotelSessionSnapshot>({
      sessionId: s.id.sessionId,
      callSid: s.id.callSid,
      streamSid: s.metadata.streamId,
      remoteAddress: s.metadata.remoteAddress,
      connectionState: s.connectionState,
      inboundSequence: s.inboundSequence,
      outboundSequence: s.outboundSequence,
      lastActivityAt: s.lastActivityAt,
      heartbeat: {
        missedPings: s.heartbeat.missedPings,
        latestRttMs: s.heartbeat.latestRttMs,
      },
    });
  }

  // ─── Lifecycle ─────────────────────────────────────────────────────────────

  async close(reason = 'requested'): Promise<void> {
    if (this._destroyed) return;
    this._destroyed = true;
    await this._gateway.close(this.sessionId, reason);
  }

  destroy(): void {
    if (this._destroyed) return;
    this._destroyed = true;
    this._gateway.disconnect(this.sessionId);
  }
}

/**
 * @module ExotelFactory
 *
 * Dependency-injected factory for creating Exotel session and adapter objects.
 *
 * ## Purpose
 * `ExotelFactory` is the single authoritative entry point for constructing
 * Exotel-specific objects. It wires together `ExotelAdapter`, `ExotelSession`,
 * and the `TransportGateway` without exposing any internal construction
 * details to the application layer.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No MediaSession imports.
 * - No business logic.
 * - All dependencies are injected.
 */

import type { WebSocket as WsWebSocket } from 'ws';
import type { ITransportGateway } from '../../transport/TransportGateway.js';
import type { IMediaSession } from '../../media/MediaSession.js';
import type { ILogger } from '../../logger/index.js';
import type { SessionId } from '../../types/index.js';
import { ExotelAdapter } from './ExotelAdapter.js';
import { ExotelSession } from './ExotelSession.js';
import type { IExotelSession } from './ExotelSession.js';

/**
 * Dependencies required to construct an `ExotelSession`.
 */
export interface ExotelSessionDependencies {
  /** The raw WebSocket accepted by the server upgrade handler. */
  readonly socket: WsWebSocket;
  /** Unique session identifier shared with the media layer. */
  readonly sessionId: SessionId;
  /** Telephony call identifier. */
  readonly callSid: string;
  /** Campaign identifier (metadata only; not used by the adapter). */
  readonly campaignId: string;
  /** The `IMediaSession` that owns this call's lifecycle. */
  readonly mediaSession: IMediaSession;
  /** IP address or hostname of the remote Exotel endpoint. */
  readonly remoteAddress: string;
  /** Structured logger. */
  readonly logger: ILogger;
}

/**
 * Public contract for the Exotel session factory.
 */
export interface IExotelFactory {
  /**
   * Creates an `ExotelSession` that binds the given WebSocket to the
   * transport gateway and the supplied `IMediaSession`.
   *
   * After this call returns, the gateway owns the connection lifecycle.
   * The caller should retain the returned `IExotelSession` only if it
   * needs to send outbound audio or close the session programmatically.
   *
   * @param deps - All per-call dependencies.
   * @returns A live `IExotelSession`.
   */
  createSession(deps: ExotelSessionDependencies): IExotelSession;
}

/**
 * Production implementation of `IExotelFactory`.
 *
 * Instantiate once at bootstrap; reuse across all calls.
 */
export class ExotelFactory implements IExotelFactory {
  private readonly _gateway: ITransportGateway;
  private readonly _adapter: ExotelAdapter;

  constructor(gateway: ITransportGateway, logger: ILogger) {
    this._gateway = gateway;
    this._adapter = new ExotelAdapter(logger);

    // Register the adapter once — the gateway is shared across all calls.
    this._gateway.registerAdapter(this._adapter);
  }

  createSession(deps: ExotelSessionDependencies): IExotelSession {
    const transportSession = this._gateway.accept(
      deps.socket,
      deps.sessionId,
      deps.callSid,
      deps.campaignId,
      'exotel',
      deps.mediaSession,
      deps.remoteAddress
    );

    return new ExotelSession(transportSession, this._gateway);
  }
}

/**
 * Convenience function — creates an `ExotelSession` using the provided factory.
 *
 * @param factory - Factory implementation to delegate to.
 * @param deps    - Per-call dependencies.
 * @returns A live `IExotelSession`.
 *
 * @example
 * ```typescript
 * const session = createExotelSession(factory, {
 *   socket,
 *   sessionId,
 *   callSid,
 *   campaignId,
 *   mediaSession,
 *   remoteAddress: req.socket.remoteAddress ?? '',
 *   logger,
 * });
 * // Call lifecycle is now managed by the gateway + MediaSession.
 * ```
 */
export function createExotelSession(
  factory: IExotelFactory,
  deps: ExotelSessionDependencies
): IExotelSession {
  return factory.createSession(deps);
}

/**
 * @module TransportFactory
 *
 * Dependency-injected factory for constructing `TransportGateway` instances.
 *
 * ## Purpose
 * `TransportFactory` is the single authoritative entry point for constructing
 * `TransportGateway` objects. It centralises all construction logic and ensures
 * the gateway is correctly configured before being handed to the application.
 *
 * ## Rules
 * - No OpenAI imports.
 * - No Audio Engine imports.
 * - No Conversation Orchestrator imports.
 * - No business logic.
 * - All dependencies are injected.
 */

import type { ILogger } from '../logger/index.js';
import { TransportGateway } from './TransportGateway.js';
import type { ITransportGateway, TransportGatewayConfig } from './TransportGateway.js';

/**
 * Public contract for the transport gateway factory.
 */
export interface ITransportFactory {
  /**
   * Creates and returns a new `ITransportGateway`.
   *
   * The returned gateway has no adapters registered. Callers must call
   * `gateway.registerAdapter(adapter)` before accepting connections.
   *
   * @param config - Optional overrides for connection-level defaults.
   * @returns A new `ITransportGateway` ready to accept connections.
   */
  createGateway(config?: Partial<TransportGatewayConfig>): ITransportGateway;
}

/**
 * Production implementation of `ITransportFactory`.
 *
 * Instantiate once at bootstrap.
 */
export class TransportFactory implements ITransportFactory {
  private readonly _logger: ILogger;

  constructor(logger: ILogger) {
    this._logger = logger;
  }

  createGateway(config: Partial<TransportGatewayConfig> = {}): ITransportGateway {
    return new TransportGateway(this._logger, config);
  }
}

/**
 * Convenience function — creates a `TransportGateway` using the given factory.
 *
 * @param factory - Factory implementation to delegate to.
 * @param config  - Optional configuration overrides.
 * @returns A new `ITransportGateway`.
 *
 * @example
 * ```typescript
 * const gateway = createTransportGateway(factory);
 * gateway.registerAdapter(exotelAdapter);
 *
 * // In WebSocket server upgrade handler:
 * server.on('upgrade', (req, socket, head) => {
 *   wss.handleUpgrade(req, socket, head, (ws) => {
 *     gateway.accept(ws, sessionId, callSid, campaignId, 'exotel', mediaSession, remoteAddress);
 *   });
 * });
 * ```
 */
export function createTransportGateway(
  factory: ITransportFactory,
  config?: Partial<TransportGatewayConfig>
): ITransportGateway {
  return factory.createGateway(config);
}

