   129→export class SessionRegistry implements ISessionRegistry {
   130→  private readonly _log: ILogger;
   131→
   132→  /** Primary store: sessionId → SessionContext */
   133→  private readonly _sessions: Map<SessionId, SessionContext> = new Map();
   134→
   135→  /** Secondary index: callSid → sessionId */
   136→  private readonly _callSidIndex: Map<CallSid, SessionId> = new Map();
   137→
   138→  /** Secondary index: phone → sessionId */
   139→  private readonly _phoneIndex: Map<string, SessionId> = new Map();
   140→
   141→  /**
   142→   * @param logger - Logger bound to the `SessionRegistry` component.
   143→   */
   144→  constructor(logger: ILogger) {
   145→    this._log = logger.child({ component: 'SessionRegistry' });
   146→  }
   147→
   148→  // ─── ISessionRegistry ───────────────────────────────────────────────────────
   149→
   150→  register(context: SessionContext): void {
   151→    const { sessionId } = context;
   152→
   153→    if (this._sessions.has(sessionId)) {
   154→      throw new Error(
   155→        `SessionRegistry: session "${sessionId}" is already registered.`
   156→      );
   157→    }
   158→
   159→    this._sessions.set(sessionId, context);
