   161→  }
   162→
   163→  unregister(sessionId: SessionId): void {
   164→    const ctx = this._sessions.get(sessionId);
   165→    if (!ctx) {
   166→      this._log.warn('Unregister called for unknown session', { sessionId });
   167→      return;
   168→    }
   169→
   170→    this._sessions.delete(sessionId);
   171→
   172→    if (ctx.callSid) {
   173→      this._callSidIndex.delete(ctx.callSid);
   174→    }
   175→
   176→    if (ctx.phone) {
   177→      this._phoneIndex.delete(ctx.phone);
   178→    }
   179→
   180→    // Sweep any orphaned callSid / phone entries pointing at this sessionId
   181→    Array.from(this._callSidIndex.entries()).forEach(([callSid, sid]) => {
   182→      if (sid === sessionId) this._callSidIndex.delete(callSid);
   183→    });
   184→    Array.from(this._phoneIndex.entries()).forEach(([phone, sid]) => {
   185→      if (sid === sessionId) this._phoneIndex.delete(phone);
   186→    });
   187→
   188→    this._log.debug('Session unregistered', { sessionId });
   189→  }
   190→
