   198→    return this._sessions.get(sessionId) ?? null;
   199→  }
   200→
   201→  getByPhone(phone: string): Nullable<SessionContext> {
   202→    const sessionId = this._phoneIndex.get(phone);
   203→    if (!sessionId) return null;
   204→    return this._sessions.get(sessionId) ?? null;
   205→  }
   206→
   207→  updateCallSid(sessionId: SessionId, callSid: CallSid): void {
   208→    if (!this._sessions.has(sessionId)) {
   209→      throw new Error(
   210→        `SessionRegistry: cannot updateCallSid — session "${sessionId}" not registered.`
   211→      );
   212→    }
   213→    this._callSidIndex.set(callSid, sessionId);
   214→    this._log.debug('CallSid index updated', { sessionId, callSid });
   215→  }
   216→
   217→  updatePhone(sessionId: SessionId, phone: string): void {
   218→    if (!this._sessions.has(sessionId)) {
   219→      throw new Error(
   220→        `SessionRegistry: cannot updatePhone — session "${sessionId}" not registered.`
   221→      );
   222→    }
   223→    this._phoneIndex.set(phone, sessionId);
   224→    this._log.debug('Phone index updated', { sessionId, phone });
   225→  }
   226→
   227→  list(): readonly SessionContext[] {
   228→    return Array.from(this._sessions.values());
   229→  }
   230→
   231→  count(): number {
   232→    return this._sessions.size;
   233→  }
