   107→  // This engine is independent of the stub AudioEngine that was placed inside
   108→  // the MediaSession at SessionFactory time.  RuntimeIntegration manages this
   109→  // engine's lifecycle via start() / stop() / destroy().
   110→  const audioEngine = createAudioEngine();
