   125→  //   • MediaSession.initialize() / start() (stub runtime → no-ops, safe)
   126→  //   • InboundAudioFlow and OutboundAudioFlow start
   127→  //   • SessionSupervisor starts
   128→  await integration.start();
   129→
   130→  logger.info('RuntimeIntegration started — [TURN-DIAGNOSTICS] collector is active', {
   131→    sessionId: ctx.sessionId,
   132→  });
   133→
   134→  // ── Step 6: Register cleanup on transport disconnect ─────────────────────────
   135→  //
   136→  // When Exotel closes the WebSocket, TransportGateway emits
   137→  // `transport.disconnected`.  Stopping the integration here guarantees
   138→  // RealtimeBridge.disconnect() fires, which:
   139→  //   • detaches TurnDiagnosticsCollector
   140→  //   • prints the [TURN-DIAGNOSTICS] CALL SUMMARY
   141→  //   • persists the JSON log to logs/call-diagnostics/
   142→  const onDisconnected = (event: TransportDisconnectedEvent): void => {
   143→    if (event.sessionId !== ctx.sessionId) return;
   144→
   145→    ctx.transportGateway.off('transport.disconnected', onDisconnected);
   146→
