   148→      sessionId: ctx.sessionId,
   149→      code: event.code,
   150→      reason: event.reason,
   151→    });
   152→
   153→    integration.stop('transport_disconnected').catch(() => {
   154→      integration.shutdown();
   155→    });
   156→  };
   157→
   158→  ctx.transportGateway.on('transport.disconnected', onDisconnected);
   159→
   160→  return integration;
   161→}
