   101→const MULAW_BIAS = 33;
   102→const MULAW_CLIP = 32635;
   103→
   104→/** Encode one 16-bit PCM sample to a μ-law byte */
   105→export function encodeMulaw(sample: number): number {
   106→  let sign = 0;
   107→  if (sample < 0) { sign = 0x80; sample = -sample; }
   108→  if (sample > MULAW_CLIP) sample = MULAW_CLIP;
   109→  sample += MULAW_BIAS;
   110→  let exp = 7;
   111→  for (let mask = 0x4000; !(sample & mask) && exp > 0; mask >>= 1) exp--;
   112→  const mantissa = (sample >> (exp + 3)) & 0x0f;
   113→  return (~(sign | (exp << 4) | mantissa)) & 0xff;
   114→}
   115→
   116→/** Decode one μ-law byte to a 16-bit PCM sample */
   117→export function decodeMulaw(mulaw: number): number {
   118→  mulaw = ~mulaw;
   119→  const sign     = mulaw & 0x80;
   120→  const exponent = (mulaw >> 4) & 0x07;
   121→  const mantissa = mulaw & 0x0f;
   122→  let sample = ((mantissa << 3) + 132) << exponent;
   123→  sample -= 132;
   124→  return sign ? -sample : sample;
   125→}
   126→
   127→/** Buffer of μ-law bytes → Int16Array of PCM samples */
   128→export function mulawToInt16(buf: Buffer): Int16Array {
   129→  const out = new Int16Array(buf.length);
   130→  for (let i = 0; i < buf.length; i++) out[i] = decodeMulaw(buf[i]);
   131→  return out;
   132→}
   133→
   134→/** Int16Array of PCM samples → Buffer of μ-law bytes */
   135→export function int16ToMulaw(pcm: Int16Array): Buffer {
   136→  const out = Buffer.allocUnsafe(pcm.length);
   137→  for (let i = 0; i < pcm.length; i++) out[i] = encodeMulaw(pcm[i]);
   138→  return out;
   139→}
