   141→// ─── PCM Resampler (linear interpolation) ────────────────────────────────────
   142→
   143→/**
   144→ * Resample PCM16 samples from srcRate to dstRate.
   145→ * Uses linear interpolation — works cleanly for integer ratio pairs (24000→8000, 8000→16000).
   146→ *
   147→ * TODO: Replace with a higher-quality resampler (e.g. libsamplerate via WASM)
   148→ *       if audio artefacts are noticeable in production calls.
   149→ */
   150→export function resamplePCM16(
   151→  samples: Int16Array,
   152→  srcRate: number,
   153→  dstRate: number
   154→): Int16Array {
   155→  if (srcRate === dstRate) return samples;
   156→  const ratio     = srcRate / dstRate;
   157→  const outLength = Math.floor(samples.length / ratio);
   158→  const out       = new Int16Array(outLength);
   159→  for (let i = 0; i < outLength; i++) {
   160→    const pos  = i * ratio;
   161→    const lo   = Math.floor(pos);
   162→    const hi   = Math.min(lo + 1, samples.length - 1);
   163→    const frac = pos - lo;
   164→    out[i]     = Math.round(samples[lo] * (1 - frac) + samples[hi] * frac);
   165→  }
   166→  return out;
   167→}
