   176→  buf.writeUInt32LE(36 + dataBytes, 4);
   177→  buf.write("WAVE", 8);
   178→  buf.write("fmt ", 12);
   179→  buf.writeUInt32LE(16, 16);
   180→  buf.writeUInt16LE(1, 20);                          // PCM
   181→  buf.writeUInt16LE(channels, 22);
   182→  buf.writeUInt32LE(sampleRate, 24);
   183→  buf.writeUInt32LE(sampleRate * channels * 2, 28);  // ByteRate
   184→  buf.writeUInt16LE(channels * 2, 32);               // BlockAlign
   185→  buf.writeUInt16LE(16, 34);                         // BitsPerSample
   186→  buf.write("data", 36);
   187→  buf.writeUInt32LE(dataBytes, 40);
   188→  for (let i = 0; i < pcm.length; i++) buf.writeInt16LE(pcm[i], 44 + i * 2);
