   305→ * this function pipes raw PCM bytes from the TTS response stream directly to
   306→ * Exotel as they arrive.  The caller hears the first syllable within ~0.3–0.8 s
   307→ * of the TTS request being sent.
   308→ *
   309→ * Pipeline per streamed chunk:
   310→ *   Incoming bytes (PCM16 24 kHz) → accumulate to alignment boundary
   311→ *   → resample to 8 kHz → split into 3200-byte chunks → send as Exotel Media events
   312→ *
   313→ * Barge-in is respected on every chunk: if session.isSpeaking is set to false
   314→ * by the media handler while we're streaming, we abort immediately.
   315→ */
   316→export async function streamTTSToExotel(
   317→  text: string,
   318→  ws: WebSocket,
   319→  session: ExotelSession
   320→): Promise<void> {
   321→  // Number of 24 kHz PCM16 bytes we accumulate before downsampling.
   322→  // 9600 bytes @ 24 kHz = ~200 ms, which downsamples to 3200 bytes @ 8 kHz.
   323→  const INPUT_BATCH = EXOTEL_CHUNK_BYTES * 3; // 9600
   324→
   325→  const apiKey = process.env.OPENAI_API_KEY;
   326→  if (!apiKey) throw new Error("OPENAI_API_KEY not set");
   327→
   328→  const resp = await fetch("https://api.openai.com/v1/audio/speech", {
   329→    method:  "POST",
   330→    headers: {
   331→      Authorization:  `Bearer ${apiKey}`,
   332→      "Content-Type": "application/json",
   333→    },
   334→    body: JSON.stringify({
   335→      model:           "tts-1",
   336→      voice:           "shimmer",
   337→      input:           text,
   338→      response_format: "pcm", // raw PCM16 LE 24 kHz — no container
   339→    }),
   340→  });
   341→
   342→  if (!resp.ok || !resp.body) {
   343→    throw new Error(`TTS streaming failed: HTTP ${resp.status}`);
   344→  }
   345→
   346→  const reader  = (resp.body as any).getReader() as ReadableStreamDefaultReader<Uint8Array>;
   347→  let remainder = Buffer.alloc(0);
   348→  // Track total 8 kHz PCM bytes sent so we can set an accurate post-speech cooldown
   349→  let total8kBytes = 0;
   350→
   351→  const sendBuf = (buf: Buffer) => {
   352→    // Ensure 2-byte alignment for PCM16 LE samples
   353→    const aligned = buf.length & ~1;
   354→    if (aligned < 2) return;
   355→    const pcm24k   = new Int16Array(buf.buffer, buf.byteOffset, aligned / 2);
   356→    const pcm8k    = resamplePCM16(pcm24k, 24000, EXOTEL_SAMPLE_RATE);
   357→    const pcm8kBuf = Buffer.from(pcm8k.buffer, pcm8k.byteOffset, pcm8k.byteLength);
   358→    for (let off = 0; off < pcm8kBuf.length; off += EXOTEL_CHUNK_BYTES) {
   359→      if (!session.isSpeaking || ws.readyState !== WebSocket.OPEN) return;
   360→      sendExotelMedia(ws, session.streamSid, pcm8kBuf.slice(off, off + EXOTEL_CHUNK_BYTES).toString("base64"));
   361→      total8kBytes += Math.min(EXOTEL_CHUNK_BYTES, pcm8kBuf.length - off);
   362→    }
   363→  };
   364→
   365→  try {
   366→    while (true) {
   367→      const { done, value } = await reader.read();
   368→      if (done) break;
   369→      if (!session.isSpeaking || ws.readyState !== WebSocket.OPEN) break;
   370→
   371→      remainder = Buffer.concat([remainder, Buffer.from(value)]);
   372→
   373→      // Flush in INPUT_BATCH-sized windows so Exotel gets steady small chunks
   374→      while (remainder.length >= INPUT_BATCH) {
   375→        if (!session.isSpeaking || ws.readyState !== WebSocket.OPEN) break;
   376→        sendBuf(remainder.slice(0, INPUT_BATCH));
   377→        remainder = remainder.slice(INPUT_BATCH);
   378→      }
   379→    }
   380→  } finally {
   381→    reader.cancel().catch(() => {});
   382→  }
   383→
   384→  // Flush any remaining bytes after stream ends
   385→  if (session.isSpeaking && remainder.length >= 2 && ws.readyState === WebSocket.OPEN) {
   386→    sendBuf(remainder);
   387→  }
   388→
   389→  // ── Post-speech cooldown ─────────────────────────────────────────────────────
   390→  // We've finished SENDING audio chunks, but Exotel is still PLAYING them.
   391→  // Set a cooldown equal to the estimated playback duration + 900 ms buffer so
   392→  // our own TTS audio doesn't echo back as inbound and cause a response spiral.
   393→  //
   394→  // Exception: if barge-in interrupted us, we already sent a Clear event which
   395→  // empties Exotel's buffer instantly.  The caller is actively speaking, so we
   396→  // must become responsive immediately — use a minimal 250 ms cooldown instead.
   397→  const playbackMs = pcm8kPlaybackMs(total8kBytes);
   398→  session.ttsPlaybackMs = playbackMs;
   399→  if (session.isSpeaking) {
   400→    // Normal completion — audio is still queued in Exotel's playout buffer
   401→    session.postSpeechCooldownUntil = Date.now() + playbackMs + 900;
   402→    log(`[exotel:${session.streamSid}] ▶ TTS done — playback ~${playbackMs} ms, cooldown +${playbackMs + 900} ms`, "ws");
   403→  } else {
   404→    // Interrupted by barge-in — Clear already flushed Exotel's buffer
   405→    session.postSpeechCooldownUntil = Date.now() + 250;
   406→    log(`[exotel:${session.streamSid}] ▶ TTS interrupted (barge-in) — minimal 250 ms cooldown`, "ws");
   407→  }
   408→}
