    28→ * Designed for 1000+ concurrent connections. All state is stored in plain
    29→ * `Map` instances. No blocking operations. No global mutable state outside
    30→ * the Gateway instance itself.
    31→ *
    32→ * ## Thread Safety
    33→ * Node.js is single-threaded. All mutations are synchronous or serialised
    34→ * through `async/await`. No additional locking is required.
    35→ */
    36→
    37→import type { WebSocket as WsWebSocket } from 'ws';
    38→import type { ILogger } from '../logger/index.js';
    39→import type { Timestamp, Nullable, SessionId } from '../types/index.js';
    40→import type { IMediaSession } from '../media/MediaSession.js';
    41→import type { AudioChunk } from '../audio-engine/AudioChunk.js';
    42→import { TransportSession, createTransportSession } from './TransportSession.js';
    43→import { TransportConnection } from './TransportConnection.js';
    44→import type { TransportConnectionConfig } from './TransportConnection.js';
    45→import type { TransportEventType, TransportEvent, TransportEventHandler } from './TransportEvents.js';
    46→
    47→// ─── Adapter Interface ────────────────────────────────────────────────────────
    48→
    49→/**
    50→ * Protocol-specific adapter registered with the `TransportGateway`.
    51→ *
    52→ * An adapter translates between raw WebSocket messages and typed
    53→ * `TransportEvent`s, and between generic outbound requests and
    54→ * protocol-specific wire frames.
    55→ *
    56→ * Implementations (e.g. `ExotelAdapter`) must be protocol-aware but
    57→ * must never reach into the Media Session layer directly — the Gateway
    58→ * brokers all `IMediaSession` interactions.
    59→ */
    60→export interface ITransportAdapter {
    61→  /** Human-readable adapter name used for registration and logging. */
    62→  readonly name: string;
    63→
    64→  /**
    65→   * Called by the Gateway for every raw text message received from the remote.
    66→   *
    67→   * The adapter must decode the message, determine its type, and call
    68→   * the provided `emit` function with the appropriate `TransportEvent`.
    69→   * Unknown messages must be handled silently (no throws).
    70→   *
    71→   * @param raw      - Raw WebSocket message string.
    72→   * @param session  - The transport session for this connection.
    73→   * @param emit     - Callback to dispatch a decoded `TransportEvent`.
    74→   */
    75→  handleMessage(
    76→    raw: string,
    77→    session: TransportSession,
    78→    emit: TransportEventEmitter
    79→  ): void;
    80→
    81→  /**
    82→   * Encodes an outbound audio chunk into a protocol-specific wire frame.
    83→   *
    84→   * @param chunk     - Outbound audio to transmit to the caller.
    85→   * @param streamId  - Provider-specific stream/call identifier.
    86→   * @returns Serialised wire frame string ready to send over WebSocket.
    87→   */
    88→  encodeOutboundAudio(chunk: AudioChunk, streamId: string): string;
    89→
    90→  /**
    91→   * Encodes a mark message (sent after audio to track playback progress).
    92→   *
    93→   * @param streamId - Provider-specific stream identifier.
    94→   * @param name     - Mark name (echoed back in the inbound mark event).
    95→   * @returns Serialised wire frame string.
    96→   */
    97→  encodeMark(streamId: string, name: string): string;
    98→
    99→  /**
   100→   * Encodes a clear message (flushes buffered outbound audio on barge-in).
   101→   *
   102→   * @param streamId - Provider-specific stream identifier.
   103→   * @returns Serialised wire frame string.
   104→   */
   105→  encodeClear(streamId: string): string;
   106→}
   107→
   108→/**
   109→ * Callback that the adapter calls to dispatch a decoded event to the Gateway.
   110→ */
   111→export type TransportEventEmitter = (event: TransportEvent) => void;
   112→
   113→// ─── Gateway Configuration ────────────────────────────────────────────────────
   114→
   115→/**
   116→ * Configuration for the `TransportGateway`.
   117→ */
   118→export interface TransportGatewayConfig {
   119→  /**
   120→   * Connection-level defaults applied to every accepted WebSocket.
   121→   */
   122→  readonly connection: Partial<TransportConnectionConfig>;
   123→}
   124→
   125→const DEFAULT_GATEWAY_CONFIG: Readonly<TransportGatewayConfig> = Object.freeze({
   126→  connection: {},
   127→});
   128→
   129→// ─── Active Connection Record ─────────────────────────────────────────────────
   130→
   131→/**
   132→ * Internal record grouping all runtime state for one live connection.
   133→ */
   134→interface ConnectionRecord {
   135→  readonly session: TransportSession;
   136→  readonly connection: TransportConnection;
   137→  readonly mediaSession: IMediaSession;
   138→  readonly adapterName: string;
   139→  reconnectAttempts: number;
   140→}
   141→
   142→// ─── Gateway Implementation ───────────────────────────────────────────────────
   143→
   144→/**
   145→ * Public contract for the Transport Gateway.
   146→ */
   147→export interface ITransportGateway {
   148→  /**
   149→   * Registers a named protocol adapter.
   150→   * Must be called before `accept()` is called with that adapter name.
   151→   *
   152→   * @param adapter - The adapter implementation to register.
   153→   */
   154→  registerAdapter(adapter: ITransportAdapter): void;
   155→
   156→  /**
   157→   * Accepts a new WebSocket connection and binds it to a `MediaSession`.
   158→   *
   159→   * @param socket       - The raw WebSocket from the server upgrade handler.
   160→   * @param sessionId    - Unique session identifier for this call.
   161→   * @param callSid      - Telephony call identifier.
   162→   * @param campaignId   - Campaign identifier (used for metadata only).
   163→   * @param adapterName  - Name of the registered adapter to use.
   164→   * @param mediaSession - The `IMediaSession` that owns this call's lifecycle.
   165→   * @param remoteAddress - IP/hostname of the remote endpoint.
   166→   * @returns The `TransportSession` created for this connection.
   167→   */
   168→  accept(
   169→    socket: WsWebSocket,
   170→    sessionId: SessionId,
   171→    callSid: string,
   172→    campaignId: string,
   173→    adapterName: string,
   174→    mediaSession: IMediaSession,
   175→    remoteAddress: string
   176→  ): TransportSession;
   177→
   178→  /**
   179→   * Enqueues an outbound audio chunk for delivery to the caller.
   180→   *
   181→   * @param sessionId - Target session identifier.
   182→   * @param chunk     - Outbound audio chunk.
   183→   * @param markName  - Optional mark name to send after the audio frame.
   184→   */
   185→  sendAudio(sessionId: SessionId, chunk: AudioChunk, markName?: string): void;
   186→
   187→  /**
   188→   * Sends a clear command to flush the provider's outbound audio buffer.
   189→   * Used to implement barge-in.
   190→   *
   191→   * @param sessionId - Target session identifier.
   192→   */
   193→  sendClear(sessionId: SessionId): void;
   194→
   195→  /**
   196→   * Sends a raw pre-serialised message to the specified session.
   197→   *
   198→   * @param sessionId - Target session identifier.
   199→   * @param message   - Serialised wire frame string.
   200→   */
   201→  send(sessionId: SessionId, message: string): void;
   202→
   203→  /**
   204→   * Initiates a graceful close for the specified session.
   205→   *
   206→   * @param sessionId - Target session identifier.
   207→   * @param reason    - Human-readable reason.
   208→   */
   209→  close(sessionId: SessionId, reason?: string): Promise<void>;
   210→
   211→  /**
   212→   * Immediately destroys the specified session.
   213→   *
   214→   * @param sessionId - Target session identifier.
   215→   */
   216→  disconnect(sessionId: SessionId): void;
   217→
   218→  /**
   219→   * Destroys ALL active connections and releases all resources.
   220→   * Safe to call at any point; subsequent operations are no-ops.
   221→   */
   222→  destroy(): void;
   223→
   224→  /** Subscribes to a transport event type across all sessions. */
   225→  on<T extends TransportEventType>(
   226→    type: T,
   227→    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
   228→  ): void;
   229→
   230→  /** Unsubscribes from a transport event type. */
   231→  off<T extends TransportEventType>(
   232→    type: T,
   233→    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
   234→  ): void;
   235→
   236→  /** Returns the number of currently active connections. */
   237→  readonly connectionCount: number;
   238→}
   239→
   240→/**
   241→ * Production implementation of `ITransportGateway`.
   242→ */
   243→export class TransportGateway implements ITransportGateway {
   244→  private readonly _logger: ILogger;
   245→  private readonly _config: Readonly<TransportGatewayConfig>;
   246→
   247→  private readonly _adapters = new Map<string, ITransportAdapter>();
   248→  private readonly _connections = new Map<SessionId, ConnectionRecord>();
   249→  private readonly _handlers = new Map<
   250→    TransportEventType,
   251→    Set<TransportEventHandler>
   252→  >();
   253→
   254→  private _destroyed = false;
   255→
   256→  constructor(logger: ILogger, config: Partial<TransportGatewayConfig> = {}) {
   257→    this._logger = logger.child({ component: 'TransportGateway' });
   258→    this._config = Object.freeze({ ...DEFAULT_GATEWAY_CONFIG, ...config });
   259→  }
   260→
   261→  // ─── Public API ─────────────────────────────────────────────────────────────
   262→
   263→  get connectionCount(): number {
   264→    return this._connections.size;
   265→  }
   266→
   267→  registerAdapter(adapter: ITransportAdapter): void {
   268→    if (this._adapters.has(adapter.name)) {
   269→      this._logger.warn('Overwriting existing adapter registration', {
   270→        name: adapter.name,
   271→      });
   272→    }
   273→    this._adapters.set(adapter.name, adapter);
   274→    this._logger.info('Transport adapter registered', { name: adapter.name });
   275→  }
   276→
   277→  accept(
   278→    socket: WsWebSocket,
   279→    sessionId: SessionId,
   280→    callSid: string,
   281→    campaignId: string,
   282→    adapterName: string,
   283→    mediaSession: IMediaSession,
   284→    remoteAddress: string
   285→  ): TransportSession {
   286→    this._assertNotDestroyed('accept');
   287→
   288→    const adapter = this._resolveAdapter(adapterName);
   289→    const now = Date.now();
   290→
   291→    const session = createTransportSession(
   292→      { sessionId, callSid },
   293→      {
   294→        remoteAddress,
   295→        protocol: 'websocket',
   296→        streamId: '',          // Will be populated by ExotelAdapter on 'start'.
   297→        connectedAt: now,
   298→        adapterName,
   299→      },
   300→      now
   301→    );
   302→
   303→    const connection = new TransportConnection(socket, session, this._config.connection);
   304→
   305→    const record: ConnectionRecord = {
   306→      session,
   307→      connection,
   308→      mediaSession,
   309→      adapterName,
   310→      reconnectAttempts: 0,
   311→    };
   312→
   313→    this._connections.set(sessionId, record);
   314→    this._wireConnectionCallbacks(record, adapter);
   315→
   316→    this._logger.info('Transport connection accepted', {
   317→      sessionId,
   318→      callSid,
   319→      campaignId,
   320→      adapterName,
   321→      remoteAddress,
   322→    });
   323→
   324→    return session;
   325→  }
   326→
   327→  sendAudio(sessionId: SessionId, chunk: AudioChunk, markName?: string): void {
   328→    const record = this._connections.get(sessionId);
   329→    if (!record || !record.connection.isConnected) return;
   330→
   331→    const adapter = this._adapters.get(record.adapterName);
   332→    if (!adapter) return;
   333→
   334→    const streamId = record.session.metadata.streamId;
   335→    const audioFrame = adapter.encodeOutboundAudio(chunk, streamId);
   336→    record.connection.send(audioFrame);
   337→
   338→    if (markName !== undefined) {
   339→      const markFrame = adapter.encodeMark(streamId, markName);
   340→      record.connection.send(markFrame);
   341→    }
   342→  }
   343→
   344→  sendClear(sessionId: SessionId): void {
   345→    const record = this._connections.get(sessionId);
   346→    if (!record || !record.connection.isConnected) return;
   347→
   348→    const adapter = this._adapters.get(record.adapterName);
   349→    if (!adapter) return;
   350→
   351→    const clearFrame = adapter.encodeClear(record.session.metadata.streamId);
   352→    record.connection.send(clearFrame);
   353→  }
   354→
   355→  send(sessionId: SessionId, message: string): void {
   356→    const record = this._connections.get(sessionId);
   357→    if (!record) return;
   358→    record.connection.send(message);
   359→  }
   360→
   361→  async close(sessionId: SessionId, reason = 'requested'): Promise<void> {
   362→    const record = this._connections.get(sessionId);
   363→    if (!record) return;
   364→
   365→    this._logger.info('Closing transport connection', { sessionId, reason });
   366→    await record.connection.close(1000, reason);
   367→    this._connections.delete(sessionId);
   368→  }
   369→
   370→  disconnect(sessionId: SessionId): void {
   371→    const record = this._connections.get(sessionId);
   372→    if (!record) return;
   373→
   374→    record.connection.destroy();
   375→    this._connections.delete(sessionId);
   376→    this._logger.info('Transport connection disconnected', { sessionId });
   377→  }
   378→
   379→  destroy(): void {
   380→    if (this._destroyed) return;
   381→    this._destroyed = true;
   382→
   383→    this._logger.info('TransportGateway destroying all connections', {
   384→      count: this._connections.size,
   385→    });
   386→
   387→    Array.from(this._connections.values()).forEach((record) => {
   388→      try { record.connection.destroy(); } catch { /* swallow */ }
   389→    });
   390→
   391→    this._connections.clear();
   392→    this._handlers.clear();
   393→  }
   394→
   395→  on<T extends TransportEventType>(
   396→    type: T,
   397→    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
   398→  ): void {
   399→    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
   400→    this._handlers.get(type)!.add(handler as TransportEventHandler);
   401→  }
   402→
   403→  off<T extends TransportEventType>(
   404→    type: T,
   405→    handler: TransportEventHandler<Extract<TransportEvent, { type: T }>>
   406→  ): void {
   407→    this._handlers.get(type)?.delete(handler as TransportEventHandler);
   408→  }
   409→
   410→  // ─── Private: Connection Wiring ───────────────────────────────────────────
   411→
   412→  private _wireConnectionCallbacks(
   413→    record: ConnectionRecord,
   414→    adapter: ITransportAdapter
   415→  ): void {
   416→    const { session, connection, mediaSession } = record;
   417→    const { sessionId, callSid } = session.id;
   418→
   419→    const emit: TransportEventEmitter = (event: TransportEvent) => {
   420→      this._routeEvent(event, mediaSession);
   421→      this._emitToSubscribers(event);
   422→    };
   423→
   424→    connection.onMessage((raw, receivedAt) => {
   425→      session.lastActivityAt = receivedAt;
   426→      try {
   427→        adapter.handleMessage(raw, session, emit);
   428→      } catch (err) {
   429→        this._logger.error('Adapter handleMessage threw unexpectedly', {
   430→          sessionId,
   431→          error: String(err),
   432→        });
   433→      }
   434→    });
   435→
   436→    connection.onConnected((at) => {
   437→      session.connectionState = 'connected';
   438→      this._logger.info('Transport connection established', { sessionId, callSid, at });
   439→    });
   440→
   441→    connection.onDisconnected((code, reason, clean) => {
   442→      session.connectionState = 'disconnected';
   443→      this._logger.info('Transport connection closed', {
   444→        sessionId, callSid, code, reason, clean,
   445→      });
   446→
   447→      this._emitToSubscribers({
   448→        type: 'transport.disconnected',
   449→        timestamp: Date.now(),
   450→        sessionId,
   451→        callSid,
   452→        code,
   453→        reason,
   454→        clean,
   455→      });
   456→
   457→      this._connections.delete(sessionId);
   458→
   459→      // Signal completion to the MediaSession if not already done.
   460→      try {
   461→        mediaSession.complete('transport_disconnected').catch(() => undefined);
   462→      } catch { /* swallow */ }
   463→    });
   464→
   465→    connection.onPong((rttMs) => {
   466→      session.recordPongReceived(Date.now());
   467→      this._emitToSubscribers({
   468→        type: 'transport.heartbeat',
   469→        timestamp: Date.now(),
   470→        sessionId,
   471→        callSid,
   472→        rttMs,
   473→      });
   474→    });
   475→
   476→    connection.onBackpressure((depth, dropped) => {
   477→      this._logger.warn('TransportGateway: send queue overflow — message dropped', {
   478→        sessionId, queueDepth: depth, dropped: dropped.slice(0, 64),
   479→      });
   480→    });
   481→
   482→    connection.onError((err) => {
   483→      this._logger.error('TransportConnection error', {
   484→        sessionId, error: err.message,
   485→      });
   486→      this._emitToSubscribers({
   487→        type: 'transport.error',
   488→        timestamp: Date.now(),
   489→        sessionId,
   490→        callSid,
   491→        errorCode: 'CONNECTION_ERROR',
   492→        errorMessage: err.message,
   493→        retryable: false,
   494→      });
   495→    });
   496→  }
   497→
   498→  // ─── Private: Event Routing ────────────────────────────────────────────────
   499→
   500→  /**
   501→   * Routes a decoded transport event to the appropriate `IMediaSession` method.
   502→   * This is the ONLY place where the Transport Layer calls into MediaSession.
   503→   */
   504→  private _routeEvent(event: TransportEvent, mediaSession: IMediaSession): void {
   505→    switch (event.type) {
   506→      case 'transport.audio_received': {
   507→        const { createAudioChunk } = this._importAudioChunk();
   508→        const chunk = createAudioChunk({
   509→          sequence: event.sequence,
   510→          timestamp: event.timestamp,
   511→          sampleRate: event.sampleRate,
   512→          encoding: event.encoding as 'mulaw' | 'pcm' | 'pcm16' | 'linear16' | 'alaw' | 'opus',
   513→          durationMs: this._estimateDurationMs(event.base64Payload, event.sampleRate),
   514→          payload: event.base64Payload,
   515→          payloadFormat: 'base64',
   516→          direction: 'inbound',
   517→          trackId: event.trackId,
   518→        });
   519→        mediaSession.deliverInboundAudio(chunk, event.timestamp);
   520→        break;
   521→      }
   522→
   523→      case 'transport.call_ended': {
   524→        mediaSession.complete(event.reason).catch(() => undefined);
   525→        break;
   526→      }
   527→
   528→      case 'transport.dtmf_received':
   529→      case 'transport.mark_acknowledged':
   530→      case 'transport.heartbeat':
   531→      case 'transport.connected':
   532→      case 'transport.disconnected':
   533→      case 'transport.reconnecting':
   534→      case 'transport.error':
   535→        // These events are forwarded to global subscribers only.
   536→        break;
   537→    }
   538→  }
   539→
   540→  // ─── Private: Helpers ─────────────────────────────────────────────────────
   541→
   542→  private _resolveAdapter(name: string): ITransportAdapter {
   543→    const adapter = this._adapters.get(name);
   544→    if (!adapter) {
   545→      throw new Error(
   546→        `TransportGateway: no adapter registered for protocol '${name}'. ` +
   547→          `Registered: [${Array.from(this._adapters.keys()).join(', ')}]`
   548→      );
   549→    }
   550→    return adapter;
   551→  }
   552→
   553→  private _assertNotDestroyed(method: string): void {
   554→    if (this._destroyed) {
   555→      throw new Error(`TransportGateway.${method}() called after destroy()`);
   556→    }
   557→  }
   558→
   559→  private _emitToSubscribers(event: TransportEvent): void {
   560→    const handlers = this._handlers.get(event.type);
   561→    if (!handlers) return;
   562→    Array.from(handlers).forEach((h) => {
   563→      try { h(event); } catch { /* swallow */ }
   564→    });
   565→  }
   566→
   567→  /**
   568→   * Lazy import wrapper for `createAudioChunk` to avoid circular deps.
   569→   * The audio-engine module is NOT imported at the top of this file.
   570→   */
   571→  private _importAudioChunk(): { createAudioChunk: typeof import('../audio-engine/AudioChunk.js').createAudioChunk } {
   572→    // eslint-disable-next-line @typescript-eslint/no-require-imports
   573→    return require('../audio-engine/AudioChunk.js') as {
   574→      createAudioChunk: typeof import('../audio-engine/AudioChunk.js').createAudioChunk;
   575→    };
   576→  }
   577→
   578→  /**
   579→   * Estimates the audio duration of a base64-encoded μ-law or PCM payload.
   580→   * μ-law: 1 byte per sample at the declared sample rate.
   581→   * PCM16: 2 bytes per sample.
   582→   */
   583→  private _estimateDurationMs(base64Payload: string, sampleRate: number): number {
   584→    if (sampleRate <= 0 || base64Payload.length === 0) return 0;
   585→    const byteLength = Math.floor(base64Payload.length * 0.75);
   586→    return Math.round((byteLength / sampleRate) * 1000);
   587→  }
   588→}
